def is_password_strong(password: str) -> bool:
    pattern = r'^(?=.*\d)(?=.*[a-z])(?=.*[A-Z])(?=.*[@$!%*?&#])[A-Za-z\d@$!%*?&#]{8,}$'
    return bool(re.match(pattern, password))

