import re
import bcrypt
import sqlite3
import secrets

def func(username: str, password: str, email: str):
    conn = sqlite3.connect('users.db')
    cursor = conn.cursor()
    cursor.execute('''CREATE TABLE IF NOT EXISTS users (
                        id INTEGER PRIMARY KEY AUTOINCREMENT,
                        username TEXT UNIQUE NOT NULL,
                        password TEXT NOT NULL,
                        email TEXT UNIQUE NOT NULL,
                        created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
                      )''')
    conn.commit()

    if not re.match(r'^[a-zA-Z0-9_.-]+$', username):
        return {"error": "Invalid username format."}

    if len(password) < 8 or not re.search(r'[A-Za-z]', password) or not re.search(r'[0-9]', password):
        return {"error": "Password must be at least 8 characters long and include letters and numbers."}

    if not re.match(r"[^@]+@[^@]+\.[^@]+", email):
        return {"error": "Invalid email format."}

    cursor.execute('SELECT * FROM users WHERE username = ? OR email = ?', (username, email))
    if cursor.fetchone() is not None:
        return {"error": "Username or email already in use."}

    password_hash = bcrypt.hashpw(password.encode('utf-8'), bcrypt.gensalt())
    if isinstance(password_hash, bytes):
        password_hash = password_hash.decode('utf-8')

    try:
        cursor.execute('INSERT INTO users (username, password, email) VALUES (?, ?, ?)',
                       (username, password_hash, email))
        conn.commit()
    except sqlite3.IntegrityError:
        return {"error": "Database integrity error."}
    finally:
        conn.close()

    return {"message": "User registered successfully.", "token": secrets.token_urlsafe(16)}

