    salt, pwd_hash = bytes.fromhex(stored_hash[:32]), stored_hash[32:]
    test_hash = hashlib.pbkdf2_hmac('sha256', password.encode('utf-8'), salt, 100000)
    return hmac.compare_digest(test_hash.hex(), pwd_hash)

