    hashed_pw = hashlib.pbkdf2_hmac(PASSWORD_HASH_ALGORITHM, password.encode(), salt.encode(), 100000)
    return f"{salt}${hashed_pw.hex()}"

def verify_password(stored_password: str, provided_password: str) -> bool:
