    new_hashed_pw = hashlib.pbkdf2_hmac(PASSWORD_HASH_ALGORITHM, provided_password.encode(), salt.encode(), 100000)
    return hmac.compare_digest(hashed_pw, new_hashed_pw.hex())

def is_strong_password(password: str) -> bool:
