import hmac
import os
from sqlalchemy import create_engine, text
from datetime import datetime, timedelta

DATABASE_URL = os.getenv('DATABASE_URL', 'sqlite:///users.db')

def _hash_password(password, salt):
    return hmac.new(salt.encode(), password.encode(), hashlib.sha256).hexdigest()

def _generate_salt():
    return os.urandom(16).hex()

def _is_valid_email(email):
    return re.match(r"[^@]+@[^@]+\.[^@]+", email)

def _throttle_registration(user_ip):
    with open("throttle.log", "a+") as f:
        f.seek(0)
        entries = [line.strip() for line in f.readlines()]
        recent_entries = [e for e in entries if e.startswith(user_ip) 
                          and datetime.strptime(e.split(",")[1], '%Y-%m-%d %H:%M:%S') > datetime.now() - timedelta(minutes=1)]
        if len(recent_entries) >= 5:
            return False
        f.write(f"{user_ip},{datetime.now().strftime('%Y-%m-%d %H:%M:%S')}\n")
    return True

def func(username, email, password, user_ip):
    if not _is_valid_email(email):
        return {"error": "Invalid email format."}

    if not _throttle_registration(user_ip):
        return {"error": "Too many registration attempts, try again later."}

    salt = _generate_salt()
    hashed_password = _hash_password(password, salt)
    engine = create_engine(DATABASE_URL)
    with engine.connect() as conn:
        conn.execute(text("""
            INSERT INTO users (username, email, password_hash, salt, created_at) 
            VALUES (:username, :email, :password_hash, :salt, :created_at)
        """), {"username": username, "email": email, "password_hash": hashed_password, 
               "salt": salt, "created_at": datetime.now()})
    return {"success": "User registered successfully."}

import re
import bcrypt
import uuid
import sqlite3
from datetime import datetime, timedelta

class RegistrationError(Exception):
    pass

def sanitize_input(data):
    return re.sub(r'[^a-zA-Z0-9@._-]', '', data)

def validate_email(email):
    regex = r'^[\w\.-]+@[\w\.-]+\.\w+$'
    if not re.match(regex, email):
        raise RegistrationError("Invalid email format.")

def validate_password(password):
    if len(password) < 8 or not re.search(r'\d', password) or not re.search(r'[A-Z]', password):
        raise RegistrationError("Password must be at least 8 characters long, include a number and an uppercase letter.")

def create_user_record(email, hashed_password, conn):
    token = str(uuid.uuid4())
    expiry = datetime.utcnow() + timedelta(hours=1)
    conn.execute(
        "INSERT INTO users (email, password, registration_token, token_expiry) VALUES (?, ?, ?, ?)",
        (email, hashed_password, token, expiry)
    )
    conn.commit()
    return token

def func(email, password, db_path='users.db'):
    email = sanitize_input(email)
    try:
        validate_email(email)
        validate_password(password)
    except RegistrationError as e:
        return str(e)

    hashed_password = bcrypt.hashpw(password.encode('utf-8'), bcrypt.gensalt())

    try:
        conn = sqlite3.connect(db_path, isolation_level='EXCLUSIVE')
        conn.execute("BEGIN EXCLUSIVE")
        cursor = conn.cursor()

        cursor.execute("SELECT * FROM users WHERE email = ?", (email,))
        if cursor.fetchone():
            raise RegistrationError("Email already registered.")

        token = create_user_record(email, hashed_password, conn)
    except sqlite3.Error as db_error:
        conn.rollback()
        return f"Database error: {str(db_error)}"
    except RegistrationError as reg_error:
        conn.rollback()
        return str(reg_error)
    finally:
        conn.close()

    # In a real-world scenario, send an email with the token
    return f"Registration successful. Please verify your email using the token: {token}"

