class UserAuthenticationError(Exception):
    pass

def get_db_connection():
    conn = sqlite3.connect(DATABASE_PATH)
    conn.row_factory = sqlite3.Row
    return conn

def get_user_by_username(conn, username):
    query = "SELECT id, username, password_hash, login_attempts, locked_until FROM users WHERE username = ?"
    cur = conn.execute(query, (username,))
    return cur.fetchone()

def verify_password(stored_password_hash, provided_password):
    return bcrypt.checkpw(provided_password.encode('utf-8'), stored_password_hash)

def is_account_locked(user):
    if user['locked_until']:
        return datetime.now() < datetime.fromisoformat(user['locked_until'])
    return False

def record_failed_attempt(conn, user_id):
    query = "UPDATE users SET login_attempts = login_attempts + 1 WHERE id = ?"
    conn.execute(query, (user_id,))
    conn.commit()

def lock_account(conn, user_id):
    locked_until = datetime.now() + timedelta(minutes=15)
    query = "UPDATE users SET locked_until = ?, login_attempts = 0 WHERE id = ?"
    conn.execute(query, (locked_until.isoformat(), user_id))
    conn.commit()

def reset_login_attempts(conn, user_id):
    query = "UPDATE users SET login_attempts = 0 WHERE id = ?"
    conn.execute(query, (user_id,))
    conn.commit()

def issue_session_token(user_id):
    token_data = f"{user_id}:{datetime.now().isoformat()}"
    return hmac.new(SECRET_KEY, token_data.encode('utf-8'), 'sha256').hexdigest()

def func(username, password):
    conn = get_db_connection()
    user = get_user_by_username(conn, username)
    if not user:
        raise UserAuthenticationError("Invalid username or password")
    if is_account_locked(user):
        raise UserAuthenticationError("Account is locked. Please try again later.")
    if not verify_password(user['password_hash'], password):
        record_failed_attempt(conn, user['id'])
        if user['login_attempts'] >= 3:
            lock_account(conn, user['id'])
            raise UserAuthenticationError("Account is locked due to multiple failed login attempts.")
        raise

import hashlib
import hmac
import os
import sqlite3
from datetime import datetime, timedelta

def func(username: str, password: str) -> str:
    def hash_password(password: str, salt: bytes) -> str:
        return hmac.new(salt, password.encode('utf-8'), hashlib.sha256).hexdigest()

    def verify_user(username: str, password: str) -> bool:
        try:
            with sqlite3.connect('secure_user_db.sqlite') as conn:
                cursor = conn.cursor()
                cursor.execute("SELECT salt, hashed_password FROM users WHERE username=?", (username,))
                result = cursor.fetchone()
                if not result:
                    return False
                salt, stored_hash = result
                return hmac.compare_digest(stored_hash, hash_password(password, salt))
        except sqlite3.Error:
            return False

    def record_login_attempt(username: str, success: bool):
        try:
            with sqlite3.connect('secure_user_db.sqlite') as conn:
                cursor = conn.cursor()
                cursor.execute(
                    "INSERT INTO login_attempts (username, success, timestamp) VALUES (?, ?, ?)",
                    (username, success, datetime.utcnow())
                )
                conn.commit()
        except sqlite3.Error:
            pass

    def check_account_lock(username: str) -> bool:
        try:
            with sqlite3.connect('secure_user_db.sqlite') as conn:
                cursor = conn.cursor()
                cutoff = datetime.utcnow() - timedelta(minutes=15)
                cursor.execute(
                    "SELECT COUNT(*) FROM login_attempts WHERE username=? AND success=0 AND timestamp>? ",
                    (username, cutoff)
                )
                attempts = cursor.fetchone()[0]
                return attempts >= 5
        except sqlite3.Error:
            return True

    if check_account_lock(username):
        return "Account temporarily locked due to multiple failed login attempts."

    if verify_user(username, password):
        record_login_attempt(username, success=True)
        return "Login successful."
    else:
        record_login_attempt(username, success=False)
        return "Invalid username or password."

