import hashlib
import hmac
import os
import psycopg2
from datetime import datetime, timedelta

class LoginError(Exception):
    pass

def func(username: str, password: str, db_conn_str: str):
    def get_user_data(conn, username):
        with conn.cursor() as cur:
            cur.execute("SELECT id, password_hash, salt, last_login FROM users WHERE username = %s", (username,))
            return cur.fetchone()

    def update_login_timestamp(conn, user_id):
        with conn.cursor() as cur:
            cur.execute("UPDATE users SET last_login = %s WHERE id = %s", (datetime.now(), user_id))

    def verify_password(stored_hash, salt, password):
        hashed_password = hmac.new(salt.encode(), password.encode(), hashlib.sha256).hexdigest()
        return hmac.compare_digest(stored_hash, hashed_password)

    def throttle_check(last_login):
        if last_login and datetime.now() - last_login < timedelta(seconds=2):
            raise LoginError("Too many login attempts. Please try again later.")

    conn = psycopg2.connect(db_conn_str)
    try:
        result = get_user_data(conn, username)
        if not result:
            raise LoginError("Invalid username or password.")
        user_id, stored_hash, salt, last_login = result
        throttle_check(last_login)
        if not verify_password(stored_hash, salt, password):
            raise LoginError("Invalid username or password.")
        update_login_timestamp(conn, user_id)
    finally:
        conn.close()
    return True

