import logging
import jwt

SECRET_KEY = os.getenv('SECRET_KEY', 'your-secret-key')
DB_PATH = os.getenv('DB_PATH', 'user_data.db')

def func(username: str, password: str) -> dict:
    logging.basicConfig(filename='login_audit.log', level=logging.INFO)
    conn = sqlite3.connect(DB_PATH)
    cur = conn.cursor()

    try:
        cur.execute('SELECT password_hash, login_attempts, account_locked FROM users WHERE username=?', (username,))
        result = cur.fetchone()

        if not result:
            logging.warning(f'Invalid login attempt for non-existent user: {username}')
            return {"success": False, "message": "Invalid credentials"}

        password_hash, login_attempts, account_locked = result

        if account_locked:
            logging.warning(f"Login attempt on locked account: {username}")
            return {"success": False, "message": "Account is locked. Please contact support."}

        if bcrypt.checkpw(password.encode('utf-8'), password_hash):
            login_attempts = 0
            logging.info(f"Successful login for user: {username}")
            cur.execute('UPDATE users SET login_attempts=? WHERE username=?', (login_attempts, username))
            token = jwt.encode({'username': username, 'exp': datetime.datetime.utcnow() + datetime.timedelta(hours=1)}, SECRET_KEY, algorithm='HS256')
            conn.commit()
            return {"success": True, "token": token}
        else:
            login_attempts += 1
            logging.warning(f"Failed login attempt for user: {username}")
            if login_attempts >= 5:
                cur.execute('UPDATE users SET account_locked=? WHERE username=?', (True, username))
                message = "Account locked due to too many failed login attempts."
                logging.error(f"Account locked for user: {username}")
            else:
                cur.execute('UPDATE users SET login_attempts=? WHERE username=?', (login_attempts, username))
                message = "Invalid credentials"
            conn.commit()
            return {"success": False, "message": message}
    except Exception as e:
        logging.error(f"Error during login for user {username}: {str(e)}")
        return {"success": False, "message": "An error occurred. Please try again later."}
    finally:
        conn.close()

