def secure_hash(password, salt=None):
    if not salt:
        salt = os.urandom(16)
    return salt, hashlib.pbkdf2_hmac('sha256', password.encode(), salt, 100000)

def verify_password(stored_password, stored_salt, provided_password):
    _, hashed_pw = secure_hash(provided_password, stored_salt)
    return hmac.compare_digest(stored_password, hashed_pw)

