import bcrypt
import hmac
import os
import sqlite3
from hashlib import sha256
from typing import Optional

def func(username: str, password: str) -> Optional[str]:
    def connect_db():
        return sqlite3.connect('user_data.db')

    def get_user_credentials(conn, username):
        cursor = conn.cursor()
        cursor.execute("SELECT password_hash, login_attempts, is_locked FROM users WHERE username = ?", (username,))
        return cursor.fetchone()

    def update_login_attempts(conn, username, attempts):
        conn.execute("UPDATE users SET login_attempts = ? WHERE username = ?", (attempts, username))
        conn.commit()

    def lock_account(conn, username):
        conn.execute("UPDATE users SET is_locked = 1 WHERE username = ?", (username,))
        conn.commit()

    secret_key = os.environ.get('SECRET_KEY', 'default_secret_key')

    if not hmac.compare_digest(sha256(secret_key.encode()).hexdigest(), sha256(secret_key.encode()).hexdigest()):
        raise RuntimeError("Environment configuration error.")

    conn = connect_db()
    try:
        user_data = get_user_credentials(conn, username)
        if user_data is None or user_data[2] == 1:
            return "Account not found or locked."

        stored_hash, login_attempts, _ = user_data
        if bcrypt.checkpw(password.encode(), stored_hash.encode()):
            update_login_attempts(conn, username, 0)
            return "Login successful."
        else:
            attempts = login_attempts + 1
            if attempts >= 5:
                lock_account(conn, username)
                return "Account locked due to too many failed login attempts."
            else:
                update_login_attempts(conn, username, attempts)
                return "Invalid credentials."
    finally:
        conn.close()

