import os
import hashlib
import hmac
import sqlite3
import time

def func(username, password, db_path='users.db'):
    if not isinstance(username, str) or not isinstance(password, str):
        return {"status": "error", "message": "Invalid input."}

    conn = sqlite3.connect(db_path)
    cursor = conn.cursor()

    cursor.execute("SELECT password_hash, salt, last_login_attempt FROM users WHERE username = ?", (username,))
    row = cursor.fetchone()

    if row is None:
        return {"status": "error", "message": "User not found."}

    stored_password_hash, salt, last_login_attempt = row
    current_time = int(time.time())

    if current_time - last_login_attempt < 5:
        return {"status": "error", "message": "Too many login attempts. Please wait a moment."}

    derived_key = hashlib.pbkdf2_hmac(
        'sha256',
        password.encode('utf-8'),
        salt.encode('utf-8'),
        100000
    )

    if hmac.compare_digest(derived_key, stored_password_hash):
        cursor.execute("UPDATE users SET last_login_attempt = ? WHERE username = ?", (current_time, username))
        conn.commit()
        session_token = os.urandom(32).hex()
        return {"status": "success", "session_token": session_token}

    cursor.execute("UPDATE users SET last_login_attempt = ? WHERE username = ?", (current_time, username))
    conn.commit()

    return {"status": "error", "message": "Invalid credentials."}

