from datetime import datetime, timedelta

def func(username: str, password: str, db_path: str) -> str:
    def hash_password(password: str, salt: bytes) -> str:
        return hmac.new(salt, password.encode(), hashlib.sha256).hexdigest()

    def validate_user_credentials(username: str, password: str) -> bool:
        connection = sqlite3.connect(db_path)
        cursor = connection.cursor()
        try:
            cursor.execute("SELECT password_hash, salt FROM users WHERE username = ?", (username,))
            row = cursor.fetchone()
            if row:
                stored_password_hash, salt = row
                return stored_password_hash == hash_password(password, salt)
            return False
        finally:
            connection.close()

    def log_login_attempt(username: str, success: bool):
        connection = sqlite3.connect(db_path)
        cursor = connection.cursor()
        try:
            cursor.execute("INSERT INTO login_attempts (username, success, timestamp) VALUES (?, ?, ?)",
                           (username, success, datetime.now()))
            connection.commit()
        finally:
            connection.close()

    def is_account_locked(username: str) -> bool:
        connection = sqlite3.connect(db_path)
        cursor = connection.cursor()
        try:
            cursor.execute("SELECT timestamp FROM login_attempts WHERE username = ? AND success = 0 ORDER BY timestamp DESC LIMIT 5", (username,))
            attempts = cursor.fetchall()
            if len(attempts) == 5 and datetime.now() - datetime.fromisoformat(attempts[-1][0]) < timedelta(minutes=15):
                return True
            return False
        finally:
            connection.close()

    if is_account_locked(username):
        return "Account is locked due to repeated failed login attempts. Please try again later."

    if validate_user_credentials(username, password):
        log_login_attempt(username, True)
        return "Login successful."
    else:
        log_login_attempt(username, False)
        return "Invalid username or password."

import hashlib
import hmac
import os
import sqlite3
import time

DATABASE = 'user_data.db'
SECRET_KEY = os.environ['SECRET_KEY']

def hash_password(password, salt):
    return hmac.new(salt.encode(), password.encode(), hashlib.sha256).hexdigest()

def authenticate_user(username, password):
    conn = sqlite3.connect(DATABASE)
    cursor = conn.cursor()
    cursor.execute("SELECT password_hash, salt FROM users WHERE username = ?", (username,))
    result = cursor.fetchone()
    conn.close()
    if not result:
        return False
    stored_hash, salt = result
    return hmac.compare_digest(stored_hash, hash_password(password, salt))

def log_attempt(username, success):
    timestamp = int(time.time())
    conn = sqlite3.connect(DATABASE)
    cursor = conn.cursor()
    cursor.execute("INSERT INTO login_attempts (username, timestamp, success) VALUES (?, ?, ?)", 
                   (username, timestamp, int(success)))
    conn.commit()
    conn.close()

def func(username, password):
    if not username or not password:
        return {'status': 'failure', 'reason': 'Invalid input'}

    if authenticate_user(username, password):
        log_attempt(username, True)
        session_token = hmac.new(SECRET_KEY.encode(), username.encode(), hashlib.sha256).hexdigest()
        return {'status': 'success', 'session_token': session_token}

    log_attempt(username, False)
    time.sleep(2)
    return {'status': 'failure', 'reason': 'Invalid credentials'}

