import hashlib
import hmac
import os
import sqlite3
from datetime import datetime, timedelta

DB_PATH = 'users.db'
SECRET_KEY = os.environ.get('SECRET_KEY', 'default_secret_key')
SESSION_DURATION = timedelta(hours=1)

def get_user_from_db(username, cursor):
    cursor.execute("SELECT id, password_hash, last_login FROM users WHERE username = ?", (username,))
    return cursor.fetchone()

def verify_password(password, stored_hash):
    return hmac.compare_digest(stored_hash, hashlib.sha256(password.encode()).hexdigest())

def update_last_login(user_id, cursor):
    cursor.execute("UPDATE users SET last_login = ? WHERE id = ?", (datetime.now(), user_id))

def setup_database():
    conn = sqlite3.connect(DB_PATH)
    cursor = conn.cursor()
    cursor.execute('''CREATE TABLE IF NOT EXISTS users (
                        id INTEGER PRIMARY KEY,
                        username TEXT UNIQUE NOT NULL,
                        password_hash TEXT NOT NULL,
                        last_login TIMESTAMP);''')
    conn.commit()
    conn.close()

def func(username, password):
    setup_database()
    conn = sqlite3.connect(DB_PATH)
    cursor = conn.cursor()

    user_data = get_user_from_db(username, cursor)
    if not user_data:
        conn.close()
        return {'status': 'error', 'message': 'Invalid username or password'}

    user_id, stored_hash, last_login = user_data

    if not verify_password(password, stored_hash):
        conn.close()
        return {'status': 'error', 'message': 'Invalid username or password'}

    expired_session = last_login is None or (datetime.now() - datetime.fromisoformat(last_login) > SESSION_DURATION)
    if expired_session:
        update_last_login(user_id, cursor)
        conn.commit()
        conn.close()
        return {'status': 'success', 'message': 'Logged in successfully, session renewed'}

    conn.close()
    return {'status': 'success', 'message': 'Logged in successfully, session active'}

import hashlib
import hmac
import sqlite3
import os
import time

def func(username, password):
    db_path = 'secure_user_db.sqlite'
    secret_key = os.environ.get('SECRET_KEY', 'default_secret_key')

    def create_connection():
        return sqlite3.connect(db_path)

    def verify_password(stored_password, provided_password):
        salt, hashed_pw = stored_password.split('$')
        expected_hash = hmac.new(secret_key.encode(), (salt + provided_password).encode(), hashlib.sha256).hexdigest()
        return hmac.compare_digest(expected_hash, hashed_pw)

    with create_connection() as conn:
        cursor = conn.cursor()
        cursor.execute('SELECT password, failed_attempts, last_failed_time FROM users WHERE username = ?', (username,))
        user_row = cursor.fetchone()

        if user_row:
            stored_password, failed_attempts, last_failed_time = user_row
            if time.time() - last_failed_time < 300 and failed_attempts >= 5:
                return 'Account locked due to too many failed attempts. Try later.'
            if verify_password(stored_password, password):
                return 'Login successful'
            else:
                failed_attempts += 1
                cursor.execute('UPDATE users SET failed_attempts = ?, last_failed_time = ? WHERE username = ?',
                               (failed_attempts, time.time(), username))
                conn.commit()
                return 'Incorrect username or password'
