import hashlib
import hmac
import os
import sqlite3
import uuid
from datetime import datetime, timedelta
from functools import wraps

DB_PATH = 'secure_audit.db'

def create_db():
    conn = sqlite3.connect(DB_PATH)
    cursor = conn.cursor()
    cursor.execute('''
        CREATE TABLE IF NOT EXISTS users (
            id TEXT PRIMARY KEY,
            username TEXT UNIQUE NOT NULL,
            password_hash TEXT NOT NULL,
            salt TEXT NOT NULL,
            last_login TIMESTAMP
        )
    ''')
    conn.commit()
    conn.close()

def hash_password(password, salt):
    return hmac.new(salt.encode(), password.encode(), hashlib.sha256).hexdigest()

def generate_salt():
    return uuid.uuid4().hex

def validate_user(username, password):
    conn = sqlite3.connect(DB_PATH)
    cursor = conn.cursor()
    cursor.execute('SELECT password_hash, salt FROM users WHERE username = ?', (username,))
    row = cursor.fetchone()
    conn.close()
    if row:
        stored_hash, salt = row
        return stored_hash == hash_password(password, salt)
    return False

def update_last_login(username):
    conn = sqlite3.connect(DB_PATH)
    cursor = conn.cursor()
    cursor.execute('UPDATE users SET last_login = ? WHERE username = ?', (datetime.utcnow(), username))
    conn.commit()
    conn.close()

def session_expired(last_login):
    return datetime.utcnow() > last_login + timedelta(hours=1)

def login_required(f):
    @wraps(f)
    def decorated_function(username, *args, **kwargs):
        conn = sqlite3.connect(DB_PATH)
        cursor = conn.cursor()
        cursor.execute('SELECT last_login FROM users WHERE username = ?', (username,))
        result = cursor.fetchone()
        conn.close()
        if result:
            last_login = datetime.strptime(result[0], '%Y-%m-%d %H:%M:%S.%f')
            if not session_expired(last_login):
                return f(username, *args, **kwargs)
        return 'Authentication required or session expired'
    return decorated_function

@login_required
def access_protected_resource(username):
    return f'Welcome, {username}. You have accessed a protected resource.'

def func(username, password):
    create_db()
    if validate_user(username, password):
        update_last_login(username)
        return access_protected_resource(username)
    return 'Invalid username or password'

