import bcrypt
import hmac
import hashlib
import os
import sqlite3
from datetime import datetime, timedelta

DATABASE_PATH = 'secure_app.db'
SESSION_EXPIRY_HOURS = 2

def hash_password(password):
    salt = bcrypt.gensalt()
    return bcrypt.hashpw(password.encode('utf-8'), salt)

def verify_password(stored_password, provided_password):
    return bcrypt.checkpw(provided_password.encode('utf-8'), stored_password)

def generate_session_token(user_id):
    secret = os.urandom(16)
    timestamp = datetime.utcnow().timestamp()
    token = f"{user_id}-{timestamp}"
    signature = hmac.new(secret, token.encode('utf-8'), hashlib.sha256).hexdigest()
    return f"{token}-{signature}"

def store_session(user_id, session_token):
    conn = sqlite3.connect(DATABASE_PATH)
    try:
        with conn:
            conn.execute(
                "INSERT INTO sessions (user_id, token, expires_at) VALUES (?, ?, ?)",
                (user_id, session_token, datetime.utcnow() + timedelta(hours=SESSION_EXPIRY_HOURS))
            )
    finally:
        conn.close()

def func(username, password):
    conn = sqlite3.connect(DATABASE_PATH)
    try:
        user_data = conn.execute(
            "SELECT id, password FROM users WHERE username = ?",
            (username,)
        ).fetchone()
        if not user_data:
            return {"success": False, "message": "Invalid credentials"}

        user_id, stored_password = user_data
        if not verify_password(stored_password, password):
            return {"success": False, "message": "Invalid credentials"}

        session_token = generate_session_token(user_id)
        store_session(user_id, session_token)
        return {"success": True, "token": session_token}

    finally:
        conn.close()

