import hashlib
import hmac
import os
import sqlite3
from datetime import datetime, timedelta

DATABASE_PATH = 'user_data.db'
SECRET_KEY = os.urandom(32)
SESSION_EXPIRY_HOURS = 2

def hash_password(password: str, salt: bytes) -> str:
    return hashlib.pbkdf2_hmac('sha256', password.encode('utf-8'), salt, 100000)

def verify_password(stored_password: str, provided_password: str, salt: bytes) -> bool:
    return hmac.compare_digest(stored_password, hash_password(provided_password, salt))

def create_session_token(user_id: int) -> str:
    return hmac.new(SECRET_KEY, f'{user_id}{datetime.utcnow()}'.encode('utf-8'), hashlib.sha256).hexdigest()

def is_session_valid(session_token: str, session_expiry: datetime) -> bool:
    return datetime.utcnow() <= session_expiry

def func(username: str, password: str) -> dict:
    conn = sqlite3.connect(DATABASE_PATH)
    try:
        cursor = conn.cursor()
        cursor.execute("SELECT id, password, salt FROM users WHERE username=?", (username,))
        user = cursor.fetchone()
        if not user:
            return {"status": "failure", "message": "Invalid username or password"}

        user_id, stored_password, salt = user
        if not verify_password(stored_password, password, salt):
            return {"status": "failure", "message": "Invalid username or password"}

        session_token = create_session_token(user_id)
        expiry_time = datetime.utcnow() + timedelta(hours=SESSION_EXPIRY_HOURS)
        cursor.execute("INSERT INTO sessions (user_id, token, expiry_time) VALUES (?, ?, ?)",
                       (user_id, session_token, expiry_time))
        conn.commit()
        return {"status": "success", "message": "Login successful", "token": session_token}
    finally:
        conn.close()

import bcrypt
import logging
import os
import sqlite3
import hmac
import hashlib
import secrets

DATABASE_PATH = '/secure/db/users.db'
LOG_FILE = '/secure/logs/authentication.log'
SECRET_KEY = secrets.token_bytes(32)

def func(username, password):
    if not (isinstance(username, str) and isinstance(password, str)):
        return {"success": False, "message": "Invalid input types"}

    try:
        connection = sqlite3.connect(DATABASE_PATH, isolation_level='EXCLUSIVE')
        cursor = connection.cursor()
        cursor.execute("SELECT username, hashed_password FROM users WHERE username=? LIMIT 1", (username,))
        user_record = cursor.fetchone()

        if not user_record:
            logging.basicConfig(filename=LOG_FILE, level=logging.WARNING)
            logging.warning(f"Failed login attempt for non-existing user: {username}")
            return {"success": False, "message": "Invalid username or password"}

        stored_username, stored_hash = user_record
        password_bytes = password.encode('utf-8')

        if not bcrypt.checkpw(password_bytes, stored_hash.encode('utf-8')):
            logging.basicConfig(filename=LOG_FILE, level=logging.WARNING)
            logging.warning(f"Failed login attempt for user: {username}")
            return {"success": False, "message": "Invalid username or password"}

        auth_token = hmac.new(SECRET_KEY, stored_username.encode('utf-8'), hashlib.sha256).hexdigest()
        logging.basicConfig(filename=LOG_FILE, level=logging.INFO)
        logging.info(f"Successful login for user: {username}. Auth token: {auth_token}")

        return {"success": True, "message": "Login successful", "auth_token": auth_token}

    except sqlite3.DatabaseError as e:
        logging.basicConfig(filename=LOG_FILE, level=logging.ERROR)
        logging.error(f"Database error occurred: {str(e)}")
        return {"success": False, "message": "Internal server error"}

    finally:
        connection.close()
        if 'cursor' in locals():
            cursor.close()

import hashlib
import hmac
import os
import sqlite3
from datetime import datetime, timedelta

class SecurityException(Exception):
    pass

class DatabaseConnection:
    def __init__(self, db_path):
        self.db_path = db_path

    def __enter__(self):
        self.conn = sqlite3.connect(self.db_path)
        self.conn.execute('PRAGMA foreign_keys = ON;')
        return self.conn

    def __exit__(self, exc_type, exc_val, exc_tb):
        self.conn.commit()
        self.conn.close()

def secure_hash(password, salt):
    return hmac.new(salt.encode(), password.encode(), hashlib.sha256).hexdigest()

def issue_token():
    return os.urandom(24).hex()

def func(username, password):
    db_path = 'user_data.db'
    with DatabaseConnection(db_path) as conn:
        cursor = conn.cursor()
        cursor.execute('SELECT salt, hashed_password, last_failed_attempt, failed_attempts FROM users WHERE username = ?', (username,))
        result = cursor.fetchone()
        if not result:
            raise SecurityException("Invalid username or password.")

        salt, db_hashed_password, last_failed_attempt, failed_attempts = result
        if last_failed_attempt and datetime.now() - datetime.strptime(last_failed_attempt, '%Y-%m-%d %H:%M:%S') < timedelta(minutes=30):
            raise SecurityException("Account temporarily locked due to multiple failed login attempts.")

        hashed_input_password = secure_hash(password, salt)
        if hashed_input_password != db_hashed_password:
            cursor.execute('UPDATE users SET failed_attempts = failed_attempts + 1, last_failed_attempt = ? WHERE username = ?', (datetime.now().strftime('%Y-%m-%d %H:%M:%S'), username))
            if failed_attempts + 1 >= 5:
                raise SecurityException("Account temporarily locked due to multiple failed login attempts.")
            raise SecurityException("Invalid username or password.")

        cursor.execute('UPDATE users SET failed_attempts = 0 WHERE username = ?', (username,))
        session_token = issue_token()
        cursor.execute('INSERT INTO sessions (username, token, created_at) VALUES (?, ?, ?)', (username, session_token, datetime.now().strftime('%Y-%m-%d %H:%M:%S')))

        return session_token

import bcrypt
import jwt
import os
import re
import sqlite3
from datetime import datetime, timedelta

DATABASE_PATH = 'user_data.db'
JWT_SECRET = os.getenv('JWT_SECRET', 'default_secret')
JWT_ALGO = 'HS256'
TOKEN_EXPIRY_MINUTES = 30

def func(username, password):
    if not re.match(r"^[A-Za-z0-9_.-]{3,20}$", username):
        return {"error": "Invalid username"}

    conn = sqlite3.connect(DATABASE_PATH)
    cursor = conn.cursor()

    cursor.execute("SELECT password_hash FROM users WHERE username = ?", (username,))
    result = cursor.fetchone()

    if result is None:
        conn.close()
        return {"error": "User not found"}

    stored_hash = result[0]

    if not bcrypt.checkpw(password.encode('utf-8'), stored_hash.encode('utf-8')):
        conn.close()
        return {"error": "Incorrect password"}

    cursor.execute("UPDATE users SET last_login = ? WHERE username = ?", (datetime.utcnow(), username))
    conn.commit()
    conn.close()

    payload = {
        "username": username,
        "exp": datetime.utcnow() + timedelta(minutes=TOKEN_EXPIRY_MINUTES)
    }

    token = jwt.encode(payload, JWT_SECRET, algorithm=JWT_ALGO)

    return {"token": token}

import hashlib
import hmac
import os
import sqlite3
from datetime import datetime, timedelta

DATABASE_PATH = 'user_data.db'
SESSION_TIMEOUT = timedelta(minutes=30)

def hash_password(password, salt):
    return hmac.new(salt.encode(), password.encode(), hashlib.sha256).hexdigest()

def validate_credentials(email, password, salt, expected_hash):
    return hmac.compare_digest(hash_password(password, salt), expected_hash)

def create_session_token():
    return hashlib.sha256(os.urandom(32)).hexdigest()

def func(email, password):
    conn = sqlite3.connect(DATABASE_PATH)
    try:
        cursor = conn.cursor()
        cursor.execute("SELECT id, salt, password_hash FROM users WHERE email = ?", (email,))
        user_record = cursor.fetchone()
        if not user_record:
            return "Invalid credentials"

        user_id, salt, stored_hash = user_record
        if not validate_credentials(email, password, salt, stored_hash):
            return "Invalid credentials"

        session_token = create_session_token()
        session_expiry = datetime.utcnow() + SESSION_TIMEOUT
        cursor.execute(
            "INSERT INTO sessions (user_id, token, expiry) VALUES (?, ?, ?)",
            (user_id, session_token, session_expiry)
        )
        conn.commit()
        return {"session_token": session_token, "expires_at": session_expiry.isoformat()}
    finally:
        conn.close()

