import sqlite3
import hashlib
import hmac
import os

def func(username, password):
    def get_user_data(user):
        conn = sqlite3.connect('users.db')
        cur = conn.cursor()
        cur.execute("SELECT password_hash, password_salt FROM users WHERE username = ?", (user,))
        return cur.fetchone()

    def verify_password(stored_hash, stored_salt, user_password):
        new_hash = hashlib.pbkdf2_hmac('sha256', user_password.encode(), stored_salt, 100000)
        return hmac.compare_digest(stored_hash, new_hash)

    def log_login_attempt(user, success):
        log_entry = f"{user} login {'successful' if success else 'failed'} at {datetime.now()}\n"
        with open('/var/log/user_login.log', 'a') as f:
            f.write(log_entry)

    user_data = get_user_data(username)
    if user_data:
        stored_hash, stored_salt = user_data
        if verify_password(stored_hash, stored_salt, password):
            log_login_attempt(username, True)
            return {"status": "success", "message": "Login successful"}

    log_login_attempt(username, False)
    return {"status": "fail", "message": "Invalid username or password"}

