import hashlib
import hmac
import os
import sqlite3
from datetime import datetime, timedelta

def func(username: str, password: str):
    def hash_password(password, salt):
        return hmac.new(salt.encode(), password.encode(), hashlib.sha256).hexdigest()

    def get_user_credentials(username, conn):
        cursor = conn.cursor()
        cursor.execute("SELECT password_hash, salt, account_locked_until FROM users WHERE username = ?", (username,))
        return cursor.fetchone()

    def record_login_attempt(username, success, conn):
        cursor = conn.cursor()
        cursor.execute("INSERT INTO login_attempts (username, success, attempt_time) VALUES (?, ?, ?)", 
                       (username, success, datetime.now()))
        conn.commit()

    def is_locked(locked_until):
        return locked_until and datetime.strptime(locked_until, "%Y-%m-%d %H:%M:%S") > datetime.now()

    conn = sqlite3.connect('/secure/db/user_data.db')
    credentials = get_user_credentials(username, conn)

    if not credentials:
        record_login_attempt(username, False, conn)
        conn.close()
        return False

    password_hash, salt, locked_until = credentials

    if is_locked(locked_until):
        conn.close()
        raise PermissionError("Account is locked. Please try again later.")

    if hmac.compare_digest(hash_password(password, salt), password_hash):
        record_login_attempt(username, True, conn)
        conn.close()
        return True
    else:
        record_login_attempt(username, False, conn)
        conn.close()
        return False

