import bcrypt
from typing import Optional
import sqlite3
import logging
import hashlib
import os

logging.basicConfig(level=logging.INFO)

def get_db_connection():
    conn = sqlite3.connect('users.db')
    conn.row_factory = sqlite3.Row
    return conn

def hash_password(password: str) -> str:
    salt = bcrypt.gensalt()
    hashed = bcrypt.hashpw(password.encode('utf-8'), salt)
    return hashed.decode('utf-8')

def verify_password(stored_password: str, provided_password: str) -> bool:
    return bcrypt.checkpw(provided_password.encode('utf-8'), stored_password.encode('utf-8'))

def get_user(username: str) -> Optional[sqlite3.Row]:
    conn = get_db_connection()
    try:
        user = conn.execute('SELECT * FROM users WHERE username = ?', (username,)).fetchone()
    finally:
        conn.close()
    return user

def log_attempt(user_info: Optional[sqlite3.Row], success: bool):
    logging.info(f"User login attempt: username={user_info['username'] if user_info else 'unknown'}, success={success}")

def generate_session_token(username: str) -> str:
    return hashlib.sha256(os.urandom(64) + username.encode('utf-8')).hexdigest()

def func(username: str, password: str) -> str:
    user = get_user(username)
    if user is None:
        log_attempt(None, False)
        return "Invalid username or password"
    if not verify_password(user['password'], password):
        log_attempt(user, False)
        return "Invalid username or password"
    session_token = generate_session_token(username)
    conn = get_db_connection()
    try:
        conn.execute('UPDATE users SET session_token = ? WHERE username = ?', (session_token, username))
        conn.commit()
    finally:
        conn.close()
    log_attempt(user, True)
    return session_token

