import hashlib
import os
import hmac
import time
import sqlite3

DATABASE_PATH = 'user_data.db'
MAX_ATTEMPTS = 5
LOCKOUT_TIME = 300

def hash_password(password, salt=None):
    if not salt:
        salt = os.urandom(16)
    hashed_pw = hashlib.pbkdf2_hmac('sha256', password.encode(), salt, 100000)
    return salt, hashed_pw

def check_password(stored_salt, stored_hash, password):
    new_hash = hashlib.pbkdf2_hmac('sha256', password.encode(), stored_salt, 100000)
    return hmac.compare_digest(stored_hash, new_hash)

def get_user_data(username):
    conn = sqlite3.connect(DATABASE_PATH)
    cur = conn.cursor()
    cur.execute("SELECT password_salt, password_hash, failed_attempts, lockout_time FROM users WHERE username = ?", (username,))
    result = cur.fetchone()
    conn.close()
    return result

def update_user_data(username, field, value):
    conn = sqlite3.connect(DATABASE_PATH)
    cur = conn.cursor()
    cur.execute(f"UPDATE users SET {field} = ? WHERE username = ?", (value, username))
    conn.commit()
    conn.close()

def func(username, password):
    user_data = get_user_data(username)
    if not user_data:
        return {'status': 'failure', 'message': 'Invalid username or password'}

    stored_salt, stored_hash, failed_attempts, lockout_time = user_data

    if failed_attempts >= MAX_ATTEMPTS and time.time() < lockout_time:
        return {'status': 'failure', 'message': 'Account locked. Please try later.'}

    if check_password(stored_salt, stored_hash, password):
        update_user_data(username, 'failed_attempts', 0)
        return {'status': 'success', 'message': 'Login successful'}

    failed_attempts += 1
    if failed_attempts >= MAX_ATTEMPTS:
        lockout_time = time.time() + LOCKOUT_TIME
        update_user_data(username, 'lockout_time', lockout_time)

    update_user_data(username, 'failed_attempts', failed_attempts)
    return {'status': 'failure', 'message': 'Invalid username or password'}

