import hmac
import os
import sqlite3
from datetime import datetime, timedelta

class UserSessionException(Exception):
    pass

class DatabaseConnectionError(Exception):
    pass

def secure_compare(val1, val2):
    return hmac.compare_digest(val1, val2)

def get_db_connection():
    try:
        conn = sqlite3.connect(os.getenv('DB_PATH', 'secure_app.db'))
        conn.row_factory = sqlite3.Row
        return conn
    except sqlite3.Error as e:
        raise DatabaseConnectionError("Failed to connect to database") from e

def generate_session_token(user_id):
    return hmac.new(os.urandom(16), bytes(user_id, 'utf-8'), hashlib.sha256).hexdigest()

def log_event(event_type, user_id, status):
    with open(os.getenv('LOG_PATH', 'user_login.log'), 'a') as log_file:
        log_file.write(f"{datetime.utcnow().isoformat()} - {event_type} - UserID: {user_id} - Status: {status}\n")

def func(username, password):
    conn = get_db_connection()
    try:
        cursor = conn.cursor()
        user_query = "SELECT id, username, password_hash, last_login FROM users WHERE username = ?"
        user = cursor.execute(user_query, (username,)).fetchone()
        if not user:
            log_event("LOGIN_ATTEMPT", username, "USER_NOT_FOUND")
            raise UserSessionException("Invalid username or password")

        if not secure_compare(user['password_hash'], hashlib.sha256(password.encode()).hexdigest()):
            log_event("LOGIN_ATTEMPT", username, "PASSWORD_MISMATCH")
            raise UserSessionException("Invalid username or password")

        token = generate_session_token(user['id'])
        update_query = "UPDATE users SET last_login = ?, session_token = ? WHERE id = ?"
        cursor.execute(update_query, (datetime.utcnow(), token, user['id']))
        conn.commit()

