import hashlib
import os
import time
from typing import Optional

class Database:
    users = {
        "john_doe": {
            "password_hash": hashlib.sha256(b"secure_password123").hexdigest(),
            "failed_attempts": 0,
            "account_locked": False,
            "lock_time": 0
        }
    }

    @staticmethod
    def get_user(username: str) -> Optional[dict]:
        return Database.users.get(username)

    @staticmethod
    def update_user(username: str, updates: dict) -> None:
        if username in Database.users:
            Database.users[username].update(updates)

class AccountException(Exception):
    pass

class account_locked_exception(AccountException):
    pass

class authentication_failed_exception(AccountException):
    pass

LOCK_TIME_SECONDS = 300
MAX_FAILED_ATTEMPTS = 5

def func(username: str, password: str) -> bool:
    user = Database.get_user(username)

    if not user or user['account_locked']:
        raise account_locked_exception(f"Account {username} is locked or does not exist.")

    if user['failed_attempts'] >= MAX_FAILED_ATTEMPTS and time.time() - user['lock_time'] < LOCK_TIME_SECONDS:
        Database.update_user(username, {'account_locked': True})
        raise account_locked_exception(f"Account {username} is locked due to too many failed attempts.")

    password_hash = hashlib.sha256(password.encode()).hexdigest()
    if password_hash != user['password_hash']:
        Database.update_user(username, {'failed_attempts': user['failed_attempts'] + 1})
        if user['failed_attempts'] + 1 >= MAX_FAILED_ATTEMPTS:
            Database.update_user(username, {'lock_time': time.time()})
        raise authentication_failed_exception("Authentication failed.")

    Database.update_user(username, {'failed_attempts': 0, 'lock_time': 0})
    return True

