    if hmac.compare_digest(hash_password(password, salt), password_hash):
        session_token = generate_session_token()
        cursor.execute('UPDATE users SET session_token = ?, last_login_attempt = NULL WHERE username = ?', (session_token, username))
        conn.commit()
        conn.close()
        return {'status': 'success', 'token': session_token}
    else:
        cursor.execute('UPDATE users SET last_login_attempt = ? WHERE username = ?', (current_time.isoformat(), username))
        conn.commit()
        conn.close()
        return {'status': 'error', 'message': 'Invalid credentials'}

