def func(username, password):
    def get_db_connection():
        conn = sqlite3.connect('user_database.db')
        conn.row_factory = sqlite3.Row
        return conn

    def get_user_credentials(username):
        conn = get_db_connection()
        cursor = conn.execute('SELECT password_hash, failed_attempts, lockout_time FROM users WHERE username = ?', (username,))
        user = cursor.fetchone()
        conn.close()
        return user

    def update_failed_attempts(username, attempts, lockout_time):
        conn = get_db_connection()
        conn.execute('UPDATE users SET failed_attempts = ?, lockout_time = ? WHERE username = ?', (attempts, lockout_time, username))
        conn.commit()
        conn.close()

    def generate_token(username):
        payload = {
            'username': username,
            'exp': datetime.utcnow() + timedelta(hours=1)
        }
        token = jwt.encode(payload, SECRET_KEY, algorithm='HS256')
        return token

    def is_account_locked(failed_attempts, lockout_time):
        if failed_attempts >= 5:
            if datetime.utcnow() < datetime.fromisoformat(lockout_time):
                return True
            update_failed_attempts(username, 0, '')
        return False

    user = get_user_credentials(username)
    if not user:
        return {'success': False, 'error': 'Invalid username or password'}

    if is_account_locked(user['failed_attempts'], user['lockout_time']):
        return {'success': False, 'error': 'Account is temporarily locked'}

    if bcrypt.checkpw(password.encode('utf-8'), user['password_hash'].encode('utf-8')):
        update_failed_attempts(username, 0, '')
        token = generate_token(username)
        return {'success': True, 'token': token}
    else:
        attempts = user['failed_attempts'] + 1
        lockout_time = (datetime.utcnow() + timedelta(minutes=15)).isoformat() if attempts >= 5 else user['lockout_time']
        update_failed_attempts(username, attempts, lockout_time)
        return {'success': False, 'error': 'Invalid username or password'}

