    pwdhash = hashlib.pbkdf2_hmac('sha256', provided_password.encode('utf-8'), salt, 100000)
    return hmac.compare_digest(stored_hash, binascii.hexlify(pwdhash).decode('utf-8'))

def generate_jwt(user_id):
