import hashlib
import hmac
import os
import sqlite3
import time
from typing import Optional

DATABASE_PATH = 'user_data.db'
SECRET_KEY = os.environ.get('SECRET_KEY', 'default_secret_key')
MAX_FAILED_ATTEMPTS = 5
LOCKOUT_TIME = 300

def get_user_data(username: str) -> Optional[dict]:
    conn = sqlite3.connect(DATABASE_PATH)
    cursor = conn.cursor()
    cursor.execute("SELECT id, username, password_hash, failed_attempts, last_failed_at FROM users WHERE username = ?", (username,))
    row = cursor.fetchone()
    conn.close()
    if row:
        return {
            'id': row[0],
            'username': row[1],
            'password_hash': row[2],
            'failed_attempts': row[3],
            'last_failed_at': row[4]
        }
    return None

def update_failed_attempts(username: str, reset: bool = False):
    conn = sqlite3.connect(DATABASE_PATH)
    cursor = conn.cursor()
    if reset:
        cursor.execute("UPDATE users SET failed_attempts = 0, last_failed_at = NULL WHERE username = ?", (username,))
    else:
        cursor.execute("UPDATE users SET failed_attempts = failed_attempts + 1, last_failed_at = ? WHERE username = ?", (int(time.time()), username))
    conn.commit()
    conn.close()

def verify_password(stored_password: str, provided_password: str) -> bool:
    return hmac.compare_digest(stored_password, hashlib.sha256(provided_password.encode()).hexdigest())

def is_account_locked(user_data: dict) -> bool:
    if user_data['failed_attempts'] >= MAX_FAILED_ATTEMPTS:
        if int(time.time()) - user_data['last_failed_at'] < LOCKOUT_TIME:
            return True
        update_failed_attempts(user_data['username'], reset=True)
    return False

def func(username: str, password: str) -> bool:
    user_data = get_user_data(username)
    if not user_data:
        return False

    if is_account_locked(user_data):
        return False

    if verify_password(user_data['password_hash'], password):
        update_failed_attempts(username, reset=True)
        return True
    else:
        update_failed_attempts(username)
        return False

