import hmac
import os
import sqlite3
from datetime import datetime, timedelta
from typing import Optional, Tuple

DATABASE_FILE = 'users.db'
SESSION_TIMEOUT_MINUTES = 30
SECRET_KEY = os.environ.get('SECRET_KEY', 'default_secret')

def secure_compare(val1: str, val2: str) -> bool:
    return hmac.compare_digest(val1.encode('utf-8'), val2.encode('utf-8'))

def hash_password(password: str) -> str:
    return bcrypt.hashpw(password.encode('utf-8'), bcrypt.gensalt()).decode('utf-8')

def check_password(hashed_password: str, password: str) -> bool:
    return bcrypt.checkpw(password.encode('utf-8'), hashed_password.encode('utf-8'))

def create_session_token(user_id: int) -> str:
    raw_token = f"{user_id}{datetime.utcnow()}{SECRET_KEY}".encode('utf-8')
    return hashlib.sha256(raw_token).hexdigest()

def record_login_attempt(user_id: int, successful: bool) -> None:
    with sqlite3.connect(DATABASE_FILE) as conn:
        conn.execute('INSERT INTO login_attempts (user_id, timestamp, successful) VALUES (?, ?, ?)', 
                     (user_id, datetime.utcnow(), successful))
        conn.commit()

def create_or_update_session(user_id: int, session_token: str) -> None:
    with sqlite3.connect(DATABASE_FILE) as conn:
        conn.execute('REPLACE INTO sessions (user_id, session_token, expiry) VALUES (?, ?, ?)',
                     (user_id, session_token, datetime.utcnow() + timedelta(minutes=SESSION_TIMEOUT_MINUTES)))
        conn.commit()

def validate_user(username: str, password: str) -> Optional[int]:
    with sqlite3.connect(DATABASE_FILE) as conn:
        cursor = conn.execute('SELECT id, password FROM users WHERE username = ?', (username,))
        user = cursor.fetchone()
    if user and check_password(user[1], password):
        return user[0]
    return None

def func(username: str, password: str) -> Optional[str]:
    user_id = validate_user(username, password)
    if user_id:
        session_token = create_session_token(user_id)
        create_or_update_session(user_id, session_token)
        record_login_attempt(user_id, True)
        return session_token
    record_login_attempt(-1, False)
    return None

