    return hmac.new(salt, password.encode(), hashlib.sha256).hexdigest()

def get_user_by_username(session, username: str):
    return session.execute(users_table.select().where(users_table.c.username == username)).fetchone()

def validate_password(stored_password: str, provided_password: str, salt: bytes) -> bool:
    return hmac.compare_digest(stored_password, hash_password(provided_password, salt))

def record_login_attempt(session, user_id: int, success: bool):
    attempts_table = Table('login_attempts', metadata, autoload_with=engine)
    session.execute(attempts_table.insert().values(
        user_id=user_id,
        timestamp=datetime.utcnow(),
        success=success
    ))
    session.commit()

