def func(user_id, session_token, db_connection_string):
    def log_security_event(event_message):
        logging.basicConfig(filename='security.log', level=logging.INFO)
        logging.info(f"{datetime.datetime.utcnow()}: {event_message}")

    def validate_inputs(user_id, session_token):
        if not isinstance(user_id, int) or not isinstance(session_token, str):
            raise ValueError("Invalid input types for user_id or session_token")

    def establish_db_connection(connection_string):
        try:
            conn = sqlite3.connect(connection_string)
            return conn
        except sqlite3.Error as e:
            log_security_event(f"Database connection error: {e}")
            raise DatabaseError("Could not establish database connection")

    def revoke_session_token(conn, user_id, session_token):
        cursor = conn.cursor()
        try:
            cursor.execute("DELETE FROM user_sessions WHERE user_id=? AND session_token=?", (user_id, session_token))
            if cursor.rowcount == 0:
                log_security_event(f"Logout failed: No active session found for user_id={user_id}")
                return False
            conn.commit()
            log_security_event(f"User {user_id} successfully logged out.")
            return True
        except sqlite3.Error as e:
            log_security_event(f"SQL error during logout: {e}")
            raise DatabaseError("SQL execution error")
        finally:
            cursor.close()

