            conn.commit()
        finally:
            conn.close()

    def log_logout_event(user_id):
        event_time = time.strftime('%Y-%m-%d %H:%M:%S', time.gmtime())
        logging.info(f"User ID {user_id} successfully logged out at {event_time}")

