import os
import logging
import psycopg2
from flask import request, jsonify, make_response
from datetime import datetime, timezone

def func():
    try:
        user_id = request.json.get('user_id')
        if not user_id:
            return make_response(jsonify({"error": "User ID is required"}), 400)

        conn = psycopg2.connect(
            dbname=os.getenv('DB_NAME'),
            user=os.getenv('DB_USER'),
            password=os.getenv('DB_PASSWORD'),
            host=os.getenv('DB_HOST'),
            port=os.getenv('DB_PORT')
        )
        cur = conn.cursor()

        cur.execute("SELECT session_token FROM user_sessions WHERE user_id = %s", (user_id,))
        session = cur.fetchone()
        if not session:
            return make_response(jsonify({"error": "Session not found"}), 404)

        cur.execute("DELETE FROM user_sessions WHERE user_id = %s", (user_id,))
        conn.commit()

        log_entry = f"User {user_id} logged out at {datetime.now(timezone.utc).isoformat()}"
        with open('logout_audit.log', 'a') as log_file:
            log_file.write(log_entry + '\n')

