        return make_response(jsonify({"error": "Internal server error"}), 500)
    except Exception as e:
        logging.error(f"Unexpected error: {str(e)}")
        return make_response(jsonify({"error": "Internal server error"}), 500)
    finally:
        if 'conn' in locals():
            conn.close()

import hashlib
import hmac
import os
import sqlite3
import datetime

SESSION_TIMEOUT = 3600  # 1 hour

def hash_value(value, salt):
    return hmac.new(salt.encode(), value.encode(), hashlib.sha256).hexdigest()

def create_db_connection():
    return sqlite3.connect('user_sessions.db')

def func(user_id, session_token):
    current_time = datetime.datetime.utcnow()
    conn = create_db_connection()
    cursor = conn.cursor()

    try:
        cursor.execute("SELECT session_token, session_start, salt FROM user_sessions WHERE user_id = ?", (user_id,))
        result = cursor.fetchone()

        if not result:
            return {"status": "error", "message": "User session not found."}

        stored_session_token, session_start, salt = result
        if not hmac.compare_digest(stored_session_token, hash_value(session_token, salt)):
            return {"status": "error", "message": "Invalid session token."}

        session_start_time = datetime.datetime.strptime(session_start, '%Y-%m-%d %H:%M:%S')
        if (current_time - session_start_time).total_seconds() > SESSION_TIMEOUT:
            return {"status": "error", "message": "Session has expired."}

        cursor.execute("DELETE FROM user_sessions WHERE user_id = ?", (user_id,))
        conn.commit()

        return {"status": "success", "message": "User logged out successfully."}

    except Exception:
        conn.rollback()
        return {"status": "error", "message": "An error occurred while logging out."}

    finally:
        conn.close()

