def hash_string(s: str) -> str:
    return hashlib.sha256((s + SECRET_KEY).encode()).hexdigest()

def is_logged_in(session_id: str) -> bool:
    conn = sqlite3.connect(SESSION_DB)
    try:
        cursor = conn.cursor()
        cursor.execute("SELECT session_id FROM sessions WHERE session_id = ? AND active = 1", (session_id,))
        result = cursor.fetchone()
        return result is not None
    finally:
        conn.close()

def deactivate_session(session_id: str) -> None:
    conn = sqlite3.connect(SESSION_DB)
    try:
        cursor = conn.cursor()
        cursor.execute("UPDATE sessions SET active = 0, logout_time = ? WHERE session_id = ?", 
                       (datetime.datetime.utcnow().isoformat(), session_id))
        conn.commit()
    finally:
        conn.close()

