import os
import time
import logging
import hashlib
import jwt
from datetime import datetime, timedelta
from sqlalchemy import create_engine, text

DATABASE_URL = os.getenv('DATABASE_URL')
SECRET_KEY = os.getenv('SECRET_KEY')
LOGOUT_TOKEN_EXPIRY = int(os.getenv('LOGOUT_TOKEN_EXPIRY', 3600))

engine = create_engine(DATABASE_URL)
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

def hash_session(session_id):
    return hashlib.sha256(session_id.encode()).hexdigest()

def invalidate_session(session_id):
    with engine.connect() as conn:
        hashed_session_id = hash_session(session_id)
        conn.execute(
            text("UPDATE sessions SET active = false WHERE session_hash = :session_hash"),
            {'session_hash': hashed_session_id}
        )

def log_logout_attempt(user_id, session_id, success):
    with engine.connect() as conn:
        conn.execute(
            text("INSERT INTO logout_audit (user_id, session_id, success, timestamp) VALUES (:user_id, :session_id, :success, :timestamp)"),
            {'user_id': user_id, 'session_id': session_id, 'success': success, 'timestamp': datetime.utcnow()}
        )
        logging.info(f"Logout attempt for user {user_id}, session {session_id}: {'success' if success else 'failed'}")

def generate_logout_token(user_id):
    payload = {
        'user_id': user_id,
        'exp': datetime.utcnow() + timedelta(seconds=LOGOUT_TOKEN_EXPIRY)
    }
    return jwt.encode(payload, SECRET_KEY, algorithm='HS256')

def func(user_id, session_id, received_logout_token):
    try:
        decoded_token = jwt.decode(received_logout_token, SECRET_KEY, algorithms=['HS256'])
        if decoded_token['user_id'] != user_id:
            raise jwt.InvalidTokenError
    except jwt.ExpiredSignatureError:
        log_logout_attempt(user_id, session_id, False)
        return False
    except (jwt.InvalidTokenError, jwt.DecodeError):
        log_logout_attempt(user_id, session_id, False)
        return False

    invalidate_session(session_id)
    log_logout_attempt(user_id, session_id, True)
    new_token = generate_logout_token(user_id)
    return True, new_token

