def clear_session(session_id):
    session_id_hashed = hash_session_id(session_id)
    conn = sqlite3.connect(DATABASE_PATH)
    cursor = conn.cursor()
    cursor.execute("DELETE FROM sessions WHERE session_id = ? AND last_access < ?", 
