from datetime import datetime, timedelta

logging.basicConfig(level=logging.INFO)

def func(user_id, session_token):
    def is_token_valid(token, expiry_duration=timedelta(hours=1)):
        try:
            issue_time = datetime.fromisoformat(token.split('-')[1])
            return datetime.utcnow() - issue_time < expiry_duration
        except (IndexError, ValueError):
            return False

    def revoke_session(user_id, session_token):
        conn = sqlite3.connect('database.db')
        cursor = conn.cursor()
        try:
            cursor.execute("DELETE FROM sessions WHERE user_id = ? AND token = ?", (user_id, session_token))
            conn.commit()
            return cursor.rowcount > 0
        finally:
            conn.close()

    if not is_token_valid(session_token):
        logging.warning(f"Attempt to logout with invalid or expired token by user_id: {user_id}")
        return False

    session_revoke_status = revoke_session(user_id, session_token)

    if session_revoke_status:
        logging.info(f"User {user_id} successfully logged out.")
    else:
        logging.error(f"Failed to revoke session for user {user_id}. Token not found or already invalid.")

    return session_revoke_status

