import logging
from datetime import datetime, timedelta
from typing import Optional

class Database:
    def __init__(self):
        self.sessions = {}

    def get_session(self, token: str) -> Optional[dict]:
        return self.sessions.get(token)

    def delete_session(self, token: str):
        if token in self.sessions:
            del self.sessions[token]

    def log_action(self, user_id: str, action: str):
        logging.info(f'User {user_id}: {action} at {datetime.now()}')

db = Database()

def func(token: str) -> bool:
    try:
        session_info = db.get_session(token)
        if session_info is None:
            return False

        now = datetime.now()
        if session_info['expiry'] < now:
            db.delete_session(token)
            return False

        user_id = session_info['user_id']
        db.delete_session(token)
        db.log_action(user_id, "Logout")
        return True
    except Exception as e:
        logging.error(f"Error during logout: {e}")
        return False

