            return False
        expected_token = hmac.new(SECRET_KEY.encode(), user_id.encode(), hashlib.sha256).hexdigest()
        return hmac.compare_digest(stored_session_token, expected_token)

    def deactivate_session(user_id):
        conn = sqlite3.connect('user_sessions.db')
        cursor = conn.cursor()
        cursor.execute("UPDATE sessions SET is_active = 0 WHERE user_id = ? AND is_active = 1", (user_id,))
        conn.commit()
        conn.close()

    if verify_session_token(user_id, session_token):
        deactivate_session(user_id)
        return {'status': 'success', 'message': 'User logged out successfully.'}
    else:
        return {'status': 'failure', 'message': 'Invalid session. Could not log out.'}

