    if not user_id or not session_token:
        logging.warning('Attempt to logout with missing credentials.')
        return False

    def validate_session(user_id, session_token, conn):
        try:
            with closing(conn.cursor()) as cursor:
                cursor.execute("SELECT session_token, is_active FROM sessions WHERE user_id = ?", (user_id,))
                result = cursor.fetchone()
                if result and result[0] == session_token and result[1]:
