    def terminate_session(user_id, conn):
        try:
            with closing(conn.cursor()) as cursor:
                cursor.execute("UPDATE sessions SET is_active = ?, logout_time = ? WHERE user_id = ?", (False, int(time.time()), user_id))
            conn.commit()
            logging.info(f"User {user_id} logged out successfully.")
