SESSION_TIMEOUT = 3600  # 1 hour
SECRET_KEY = os.environ.get('SECRET_KEY', 'default_secret_key')

def generate_csrf_token(session_token):
    return hmac.new(SECRET_KEY.encode(), session_token.encode(), 'sha256').hexdigest()

def func(session_token, csrf_token):
    if not session_token or not csrf_token:
        return {'status': 'error', 'message': 'Missing session or CSRF token.'}

    with sqlite3.connect(DATABASE_PATH) as conn:
        cursor = conn.cursor()

        cursor.execute('SELECT user_id, last_activity FROM sessions WHERE session_token=?', (session_token,))
        session = cursor.fetchone()

        if not session:
            return {'status': 'error', 'message': 'Session not found or already logged out.'}

        user_id, last_activity = session
        current_time = datetime.datetime.utcnow()
        last_activity_time = datetime.datetime.strptime(last_activity, '%Y-%m-%d %H:%M:%S')
        if (current_time - last_activity_time).total_seconds() > SESSION_TIMEOUT:
            cursor.execute('DELETE FROM sessions WHERE session_token=?', (session_token,))
            conn.commit()
            return {'status': 'error', 'message': 'Session timeout. Please login again.'}

        expected_csrf_token = generate_csrf_token(session_token)
        if not hmac.compare_digest(csrf_token, expected_csrf_token):
            return {'status': 'error', 'message': 'Invalid CSRF token.'}

        cursor.execute('DELETE FROM sessions WHERE session_token=?', (session_token,))
        conn.commit()

        logging.info(f'User {user_id} logged out successfully.')
