# Configure logging
logging.basicConfig(filename='user_activity.log', level=logging.INFO)

def func(user_id, session_token, db_path='database.db'):
    def hash_token(token):
        return sha256(token.encode()).hexdigest()

    def remove_session(user_id, session_token_hash, conn):
        cursor = conn.cursor()
        cursor.execute("DELETE FROM sessions WHERE user_id=? AND session_token=?", (user_id, session_token_hash))
        conn.commit()

    def log_logout(user_id):
        logging.info(f"User {user_id} logged out at {datetime.utcnow().strftime('%Y-%m-%d %H:%M:%S')} UTC")

    def session_timeout_check(user_id, conn):
        cursor = conn.cursor()
        cursor.execute("SELECT last_active FROM sessions WHERE user_id=?", (user_id,))
        result = cursor.fetchone()
        if result:
            last_active = datetime.strptime(result[0], '%Y-%m-%d %H:%M:%S')
            if datetime.utcnow() - last_active > timedelta(hours=2):
                remove_session(user_id, hash_token(session_token), conn)
                return True
        return False

    try:
        if not os.path.isfile(db_path):
            raise FileNotFoundError("Database file not found.")

        conn = sqlite3.connect(db_path)
        session_token_hash = hash_token(session_token)

        if session_timeout_check(user_id, conn):
            log_logout(user_id)
            return {'status': 'failed', 'reason': 'session expired'}

        remove_session(user_id, session_token_hash, conn)
        log_logout(user_id)
        return {'status': 'success', 'message': 'Logged out successfully'}

    except Exception as e:
        logging.error(f"Error during logout: {str(e)}")
        return {'status': 'error', 'message': 'An error occurred'}

    finally:
        conn.close()

