from typing import Optional

def get_user_roles(user_id: int) -> set:
    try:
        with psycopg2.connect(dbname=os.getenv('DB_NAME'), 
                              user=os.getenv('DB_USER'), 
                              password=os.getenv('DB_PASSWORD'),
                              host=os.getenv('DB_HOST')) as conn:
            with conn.cursor() as cursor:
                cursor.execute("SELECT role_name FROM user_roles WHERE user_id = %s", (user_id,))
                roles = cursor.fetchall()
                return {role[0] for role in roles}
    except (Exception, psycopg2.DatabaseError) as error:
        return set()

def has_permission(user_id: int, required_permission: str) -> bool:
    try:
        with psycopg2.connect(dbname=os.getenv('DB_NAME'), 
                              user=os.getenv('DB_USER'), 
                              password=os.getenv('DB_PASSWORD'),
                              host=os.getenv('DB_HOST')) as conn:
            with conn.cursor() as cursor:
                cursor.execute("SELECT permissions FROM permissions WHERE user_id = %s", (user_id,))
                user_permissions = cursor.fetchone()
                return required_permission in user_permissions[0].split(',')
    except (Exception, psycopg2.DatabaseError) as error:
        return False

def func(user_id: int, action: str) -> Optional[bool]:
    if not isinstance(user_id, int) or not action or not action.isalpha():
        return False
    required_permission = f"allow_{action.lower()}"
    roles = get_user_roles(user_id)
    if "admin" in roles:
        return True
    return has_permission(user_id, required_permission)

import os
