from psycopg2.extras import RealDictCursor
from functools import wraps
import logging

logging.basicConfig(level=logging.INFO)

def permission_required(permission):
    def decorator(func):
        @wraps(func)
        def wrapper(user_id, *args, **kwargs):
            if not check_permission(user_id, permission):
                logging.warning(f"User {user_id} doesn't have {permission} permission.")
                raise PermissionError("Access denied due to insufficient permissions.")
            return func(user_id, *args, **kwargs)
        return wrapper
    return decorator

def connect_to_db():
    return psycopg2.connect(
        dbname=os.getenv("DB_NAME"),
        user=os.getenv("DB_USER"),
        password=os.getenv("DB_PASSWORD"),
        host=os.getenv("DB_HOST"),
        cursor_factory=RealDictCursor
    )

def check_permission(user_id, permission):
    with connect_to_db() as conn:
        with conn.cursor() as cur:
            cur.execute("""
                SELECT EXISTS (
                    SELECT 1 FROM user_permissions
                    WHERE user_id = %s AND permission = %s
                )
            """, (user_id, permission))
            result = cur.fetchone()
            return result['exists']

