import os
from functools import wraps
from typing import Callable, Any
import jwt
import sqlite3

DATABASE_PATH = 'app.db'
SECRET_KEY = os.environ.get('SECRET_KEY', 'your-default-secret-key')

def authenticate(token: str) -> dict:
    try:
        payload = jwt.decode(token, SECRET_KEY, algorithms=['HS256'])
        return {'user_id': payload['sub'], 'roles': payload['roles']}
    except jwt.InvalidTokenError:
        raise PermissionError("Invalid authentication token.")

def db_connection():
    conn = sqlite3.connect(DATABASE_PATH)
    conn.row_factory = sqlite3.Row
    return conn

def user_has_permission(user_id: int, permission: str) -> bool:
    with db_connection() as conn:
        cursor = conn.execute("SELECT role FROM user_roles WHERE user_id = ?", (user_id,))
        roles = {row['role'] for row in cursor.fetchall()}
        if not roles:
            return False
        cursor = conn.execute("SELECT role FROM role_permissions WHERE permission = ?", (permission,))
        required_roles = {row['role'] for row in cursor.fetchall()}
        return bool(roles.intersection(required_roles))

def permission_required(permission: str):
    def decorator(func: Callable):
        @wraps(func)
        def wrapper(*args: Any, **kwargs: Any) -> Any:
            token = kwargs.get('token') or args[0] if args else None
            if not token:
                raise PermissionError("Token is required")
            user_info = authenticate(token)
            if not user_has_permission(user_info['user_id'], permission):
                raise PermissionError("You do not have permission to perform this action.")
            return func(*args, **kwargs)
        return wrapper
    return decorator

@permission_required('access_sensitive_data')
def func(token: str, data_id: int):
    with db_connection() as conn:
        cursor = conn.execute("SELECT * FROM sensitive_data WHERE id = ?", (data_id,))
        data = cursor.fetchone()
        if data is None:
            raise ValueError("Data not found.")
        return dict(data)

import os
from typing import List, Dict
import psycopg2
from psycopg2.extras import DictCursor
import logging

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

DATABASE_URL = os.getenv('DATABASE_URL', 'postgresql://user:password@localhost/mydatabase')

def connect_db():
    try:
        return psycopg2.connect(DATABASE_URL, cursor_factory=DictCursor)
    except Exception as e:
        logger.error("Database connection failed: %s", e)
        raise

def sanitize_input(input_value: str) -> str:
    return input_value.replace("'", "''").replace(";", "")

def perform_permission_query(user_id: str, resource_id: str) -> Dict:
    sanitized_user_id = sanitize_input(user_id)
    sanitized_resource_id = sanitize_input(resource_id)
    query = f"""
        SELECT permissions FROM user_permissions
        WHERE user_id = '{sanitized_user_id}' AND resource_id = '{sanitized_resource_id}'
    """
    with connect_db() as conn:
        with conn.cursor() as cursor:
            cursor.execute(query)
            result = cursor.fetchone()
            return result if result else {}

def check_permission(user_permissions: Dict, required_permission: str) -> bool:
    permissions = user_permissions.get('permissions', [])
    return required_permission in permissions

def func(user_id: str, resource_id: str, required_permission: str) -> bool:
    try:
        user_permissions = perform_permission_query(user_id, resource_id)
        if user_permissions:
            has_permission = check_permission(user_permissions, required_permission)
            logger.info("User %s has %s permission for resource %s: %s",
                        user_id, required_permission, resource_id, has_permission)
            return has_permission
        else:
            logger.warning("No permissions found for user %s on resource %s", user_id, resource_id)
            return False
    except Exception as e:
        logger.error("Permission check failed: %s", e)
        return False

