import os
import hashlib
import sqlite3

def get_user_permissions(user_id, conn):
    query = "SELECT permissions FROM users WHERE id = ?"
    cursor = conn.execute(query, (user_id,))
    row = cursor.fetchone()
    return set(row[0].split(',')) if row else set()

def hash_file(filepath):
    sha256 = hashlib.sha256()
    with open(filepath, "rb") as f:
        for block in iter(lambda: f.read(4096), b""):
            sha256.update(block)
    return sha256.hexdigest()

def func(user_id, resource, action, conn, audit_log_path):
    if not isinstance(user_id, int) or not user_id > 0:
        raise ValueError("Invalid user ID")

    valid_actions = {'read', 'write', 'delete'}
    if action not in valid_actions:
        raise ValueError("Invalid action requested")

    user_permissions = get_user_permissions(user_id, conn)
    required_permission = f"{action}_{resource}"

    if required_permission not in user_permissions:
        return {"status": "denied", "reason": "insufficient_permissions"}

    try:
        with open(audit_log_path, 'a') as log_file:
            log_entry = f"{user_id} performed {action} on {resource}"
            log_file.write(log_entry + '\n')
            log_file.write(f"Hash: {hash_file(audit_log_path)}\n")

        return {"status": "allowed", "message": "permission_granted"}
    except IOError:
        return {"status": "error", "message": "audit_logging_failed"}

import os
import logging
from datetime import datetime
from sqlalchemy import create_engine, text
from sqlalchemy.exc import SQLAlchemyError

DATABASE_URI = os.getenv('DATABASE_URI')
ADMIN_ROLE = 'admin'
AUDIT_LOG_PATH = '/var/log/permissions_audit.log'

engine = create_engine(DATABASE_URI)

def log_audit(username, resource, action, result):
    try:
        with open(AUDIT_LOG_PATH, 'a') as log_file:
            log_file.write(f"{datetime.utcnow().isoformat()} - {username} - {resource} - {action} - {result}\n")
    except IOError as e:
        logging.error(f"Failed to write audit log: {e}")

def query_user_permissions(username):
    try:
        with engine.connect() as connection:
            result = connection.execute(
                text("SELECT p.resource, p.action FROM permissions p "
                     "JOIN user_roles ur ON p.role_id = ur.role_id "
                     "WHERE ur.username = :username"),
                {"username": username}
            )
            return {(row['resource'], row['action']) for row in result}
    except SQLAlchemyError as e:
        logging.error(f"Database error: {e}")
        return set()

def func(username, resource, action):
    if not isinstance(username, str) or not isinstance(resource, str) or not isinstance(action, str):
        raise ValueError("Invalid input type")

    if len(username) > 50 or len(resource) > 100 or len(action) > 100:
        raise ValueError("Input exceeds maximum length")

    if ';' in username or ';' in resource or ';' in action:
        raise ValueError("Input contains invalid characters")

    permissions = query_user_permissions(username)
    if (resource, action) in permissions or ADMIN_ROLE in permissions:
        log_audit(username, resource, action, "ALLOWED")
        return True
    else:
        log_audit(username, resource, action, "DENIED")
        return False

