import os
import logging
from functools import wraps
from sqlalchemy import create_engine, select, Table, MetaData
from sqlalchemy.exc import SQLAlchemyError

DATABASE_URL = os.getenv('DATABASE_URL', 'sqlite:///secure.db')
engine = create_engine(DATABASE_URL)
metadata = MetaData(bind=engine)
permissions_table = Table('permissions', metadata, autoload_with=engine)

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

def audit_log(user, permission, granted):
    action = "GRANTED" if granted else "DENIED"
    logger.info(f"AUDIT: User '{user}' permission '{permission}' {action}")

def permission_required(permission):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            user = kwargs.get('user', None)
            if not user:
                raise ValueError("User must be provided")
            try:
                with engine.connect() as conn:
                    query = select(permissions_table.c.permission).where(
                        permissions_table.c.user == user,
                        permissions_table.c.permission == permission
                    )
                    result = conn.execute(query).fetchone()
                    if result:
                        audit_log(user, permission, granted=True)
                        return func(*args, **kwargs)
                    else:
                        audit_log(user, permission, granted=False)
                        raise PermissionError("Permission denied")
            except SQLAlchemyError as e:
                logger.error("Database error occurred", exc_info=e)
                raise RuntimeError("Internal server error")
        return wrapper
    return decorator

