        query = select([permissions_table.c.data]).where(
            permissions_table.c.id == data_id
        )
        result = conn.execute(query).fetchone()
        if result:
            logger.info(f"Accessed sensitive data: {result['data']}")
            return result['data']
        else:
            raise ValueError("Data not found")

