import os
import logging
from functools import wraps
from typing import Callable
import jwt
import psycopg2
from psycopg2 import sql

DATABASE_URL = os.getenv('DATABASE_URL')
SECRET_KEY = os.getenv('SECRET_KEY')

def db_connection():
    return psycopg2.connect(DATABASE_URL)

def enforce_https(func: Callable) -> Callable:
    @wraps(func)
    def wrapper(*args, **kwargs):
        request = args[0]
        if not request.is_secure:
            logging.warning("Non-secure connection attempt")
            raise ConnectionError("HTTPS is required for this endpoint")
        return func(*args, **kwargs)
    return wrapper

def decode_jwt(token: str):
    try:
        return jwt.decode(token, SECRET_KEY, algorithms=['HS256'])
    except jwt.ExpiredSignatureError:
        logging.error("Expired token")
        raise PermissionError("Token has expired")
    except jwt.DecodeError:
        logging.error("Token decode failure")
        raise PermissionError("Invalid token")

@enforce_https
def func(request):
    auth_header = request.headers.get('Authorization')
    if not auth_header or not auth_header.startswith("Bearer "):
        logging.warning("Missing or malformed token")
        raise PermissionError("Authorization header missing or malformed")

    token = auth_header.split(" ")[1]
    user_info = decode_jwt(token)

    user_id = user_info.get('sub')
    resource_id = request.params.get('resource_id')

    with db_connection() as conn:
        with conn.cursor() as cursor:
            query = sql.SQL("""
                SELECT permissions FROM user_permissions
                WHERE user_id = %s AND resource_id = %s
            """)
            cursor.execute(query, (user_id, resource_id))
            result = cursor.fetchone()

    if not result:
        logging.warning("Access denied for user_id: %s", user_id)
        raise PermissionError("Access denied")

    permissions = result[0]
    required_permission = 'read'
    if required_permission not in permissions:
        logging.warning("Insufficient permissions for user_id: %s", user_id)
        raise PermissionError("Insufficient permissions")

    return {"status": "success", "message": "Permission granted"}

import os
import hashlib
import hmac
import sqlite3
from typing import Optional

def get_user_permissions(user_id: int, db_connection: sqlite3.Connection) -> Optional[set]:
    cursor = db_connection.cursor()
    cursor.execute("SELECT permissions FROM users WHERE id = ?", (user_id,))
    row = cursor.fetchone()
    return set(row[0].split(',')) if row else None

def verify_token(user_id: int, token: str, secret_key: str) -> bool:
    expected_token = hmac.new(secret_key.encode(), str(user_id).encode(), hashlib.sha256).hexdigest()
    return hmac.compare_digest(expected_token, token)

def func(user_id: int, action: str, token: str, db_path: str, secret_key: str) -> bool:
    if not os.path.exists(db_path):
        return False
    conn = sqlite3.connect(db_path)
    try:
        if not verify_token(user_id, token, secret_key):
            return False
        user_permissions = get_user_permissions(user_id, conn)
        if not user_permissions:
            return False
        return action in user_permissions
    finally:
        conn.close()

