import os
import logging
from typing import List
from sqlalchemy.orm import sessionmaker
from sqlalchemy import create_engine, select
from sqlalchemy.exc import SQLAlchemyError
from models import User, Permission

DATABASE_URL = os.getenv('DATABASE_URL')
LOG_FILE = os.getenv('LOG_FILE', 'app.log')
logging.basicConfig(filename=LOG_FILE, level=logging.INFO)

def get_db_session():
    engine = create_engine(DATABASE_URL)
    Session = sessionmaker(bind=engine)
    return Session()

def verify_user_role(user_id: int, required_roles: List[str]) -> bool:
    session = get_db_session()
    try:
        user = session.query(User).filter(User.id == user_id).one_or_none()
        if not user:
            return False
        for role in required_roles:
            if role in user.roles:
                return True
        return False
    except SQLAlchemyError as e:
        logging.error(f"Database error: {e}")
        return False
    finally:
        session.close()

def verify_user_permission(user_id: int, permission_code: str) -> bool:
    session = get_db_session()
    try:
        stmt = select(Permission).where(Permission.code == permission_code)
        permission = session.scalar(stmt)
        if not permission:
            return False
        return permission in session.query(User).filter(User.id == user_id).one().permissions
    except SQLAlchemyError as e:
        logging.error(f"Database error: {e}")
        return False
    finally:
        session.close()

def func(user_id: int, action: str) -> bool:
    action_required_roles = {
        'read': ['viewer', 'editor', 'admin'],
        'write': ['editor', 'admin'],
        'delete': ['admin']
    }
    action_required_permission = f"can_{action}"

    if action not in action_required_roles:
        logging.warning(f"Invalid action requested: {action}")
        return False

    if not verify_user_role(user_id, action_required_roles[action]):
