import os
import sqlite3
from hashlib import pbkdf2_hmac
from hmac import compare_digest
from typing import Optional

def func(user_id: int, resource_id: str, action: str, db_path: str = 'permissions.db') -> bool:
    def hash_password(password: str, salt: bytes = os.urandom(16)) -> bytes:
        return pbkdf2_hmac('sha256', password.encode(), salt, 100000), salt

    def check_password(stored_hash: bytes, salt: bytes, password: str) -> bool:
        new_hash, _ = hash_password(password, salt)
        return compare_digest(stored_hash, new_hash)

    def authenticate_user(user_id: int, db_conn) -> Optional[str]:
        cursor = db_conn.cursor()
        cursor.execute("SELECT password_hash, salt FROM users WHERE id = ?", (user_id,))
        row = cursor.fetchone()
        if row:
            stored_hash, salt = row
            if check_password(stored_hash, salt, os.getenv('USER_PASSWORD', '')):
                return 'user_authenticated'
        return None

    def has_permission(auth_token: str, resource_id: str, action: str, db_conn) -> bool:
        if auth_token:
            cursor = db_conn.cursor()
            cursor.execute("""
                SELECT 1 FROM permissions 
                WHERE user_id = ? AND resource_id = ? AND action = ?
            """, (user_id, resource_id, action))
            return cursor.fetchone() is not None
        return False

    if not os.path.exists(db_path):
        return False

    with sqlite3.connect(db_path) as conn:
        auth_token = authenticate_user(user_id, conn)
        if not auth_token:
            return False
        if has_permission(auth_token, resource_id, action, conn):
            return True
    return False

