# Database connection context manager
class DatabaseConnection:
    def __enter__(self):
        self.conn = sqlite3.connect(DATABASE_PATH)
        self.cursor = self.conn.cursor()
        return self.cursor

    def __exit__(self, exc_type, exc_value, traceback):
        self.conn.commit()
        self.conn.close()

# Hash comparison for bcrypt
def verify_password(stored_password, provided_password):
    return bcrypt.checkpw(provided_password.encode(), stored_password.encode())

# Decorator for permission check
def permission_required(role):
    def decorator(f):
        @wraps(f)
        def decorated_function(user_id, *args, **kwargs):
            with DatabaseConnection() as db:
                db.execute("SELECT role, password_hash FROM users WHERE id = ?", (user_id,))
                user = db.fetchone()
                if not user:
                    logging.warning(f"User ID {user_id} not found for permission check.")
                    raise PermissionError("User not found")

                user_role, password_hash = user
                if user_role != role:
                    logging.warning(f"User ID {user_id} does not have the required role: {role}")
                    raise PermissionError("Insufficient permissions")

                provided_password = kwargs.get('password')
                if not verify_password(password_hash, provided_password):
                    logging.warning(f"Password verification failed for User ID {user_id}.")
                    raise PermissionError("Invalid credentials")

                logging.info(f"Permission check passed for User ID {user_id}.")
                return f(*args, **kwargs)

        return decorated_function
    return decorator

