from psycopg2.extras import RealDictCursor

DATABASE_URL = os.getenv('DATABASE_URL')
ADMIN_USERS = os.getenv('ADMIN_USERS', '').split(',')

def func(user_id: str, resource_id: str) -> bool:
    def has_permission(user_roles, resource_permissions):
        return any(role in resource_permissions for role in user_roles)

    def is_admin(user_id):
        return user_id in ADMIN_USERS

    connection = None
    try:
        connection = psycopg2.connect(DATABASE_URL, cursor_factory=RealDictCursor)
        with connection.cursor() as cursor:
            cursor.execute("SELECT roles FROM users WHERE user_id = %s", (user_id,))
            user_data = cursor.fetchone()
            if not user_data:
                return False

            cursor.execute("SELECT permissions FROM resources WHERE resource_id = %s", (resource_id,))
            resource_data = cursor.fetchone()
            if not resource_data:
                return False

            user_roles = user_data['roles']
            resource_permissions = resource_data['permissions']

            if is_admin(user_id) or has_permission(user_roles, resource_permissions):
                return True
            return False

    except Exception as ex:
        return False
    finally:
        if connection:
            connection.close()

