def hash_file_contents(file_path):
    sha256_hash = hashlib.sha256()
    with open(file_path, "rb") as f:
        for byte_block in iter(lambda: f.read(4096), b""):
            sha256_hash.update(byte_block)
    return sha256_hash.hexdigest()

def validate_permission(user_permissions, required_permission):
    if required_permission not in user_permissions:
        raise PermissionError("User lacks the required permission")

def func(user_id, required_permission, resource_path):
    if not os.path.exists(resource_path):
        raise FileNotFoundError("Resource does not exist")

    db_connection = sqlite3.connect('user_permissions.db')
    user_permissions = get_user_permissions(user_id, db_connection)

    validate_permission(user_permissions, required_permission)

    resource_hash = hash_file_contents(resource_path)

    return f"Access granted. Resource hash: {resource_hash}"

import os
import sqlite3
from hashlib import sha256
import hmac

SECRET_KEY = os.environ.get('SECRET_KEY', 'default_secret_key')

def get_user_permissions(user_id):
    conn = sqlite3.connect('database.db')
    cursor = conn.cursor()
    cursor.execute("SELECT permissions FROM users WHERE id=?", (user_id,))
    result = cursor.fetchone()
    conn.close()
    if result is None:
        return []
    return result[0].split(',')

def has_permission(user_id, permission, provided_hmac):
    permissions = get_user_permissions(user_id)
    permissions_data = ','.join(sorted(permissions))
    hmac_signature = hmac.new(SECRET_KEY.encode(), permissions_data.encode(), sha256).hexdigest()
    if not hmac.compare_digest(hmac_signature, provided_hmac):
        raise PermissionError("Invalid HMAC signature.")
    return permission in permissions

def func(user_id, permission, provided_hmac):
    try:
        if has_permission(user_id, permission, provided_hmac):
            return "Permission granted."
        else:
            return "Permission denied."
    except PermissionError as e:
        return str(e)

import os
import logging
from functools import wraps
import sqlite3

logging.basicConfig(level=logging.INFO)

def func(user_id, resource_id, action):
    def permission_required(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            if not has_permission(user_id, resource_id, action):
                log_unauthorized_access(user_id, resource_id, action)
                return {"status": "error", "message": "Unauthorized access"}
            return func(*args, **kwargs)
        return wrapper

    def has_permission(user_id, resource_id, action):
        db_path = os.getenv("PERMISSION_DB_PATH", "permissions.db")
        conn = sqlite3.connect(db_path)
        query = """
            SELECT COUNT(*)
            FROM permissions
            WHERE user_id = ?
            AND resource_id = ?
            AND action = ?
        """
        cursor = conn.execute(query, (user_id, resource_id, action))
        result = cursor.fetchone()
        conn.close()
        return result[0] > 0

    def log_unauthorized_access(user_id, resource_id, action):
        logging.warning(f"Unauthorized access attempt by user {user_id} to {resource_id} for action {action}")

    @permission_required
    def perform_action():
        logging.info(f"User {user_id} performed {action} on {resource_id}")
        return {"status": "success", "message": "Action completed"}

    return perform_action()

import os
import sqlite3
from functools import wraps
from flask import request, abort

def func(user_id, resource_id, action):
    def permission_required(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            if not is_permitted(user_id, resource_id, action):
                abort(403)
            return f(*args, **kwargs)
        return decorated_function

    @permission_required
    def access_resource():
        return f"Access granted for {action} on resource {resource_id} by user {user_id}"

    return access_resource()

def is_permitted(user_id, resource_id, action):
    if not isinstance(user_id, int) or not isinstance(resource_id, int):
        return False
    if action not in {"read", "write", "delete"}:
        return False
    conn = sqlite3.connect('app.db')
    try:
        cursor = conn.cursor()
        cursor.execute("""
            SELECT EXISTS(SELECT 1 FROM permissions WHERE user_id=? AND resource_id=? AND action=?)
        """, (user_id, resource_id, action))
        result = cursor.fetchone()
    finally:
        conn.close()
    return result[0] == 1

