        abort(400)

import os
import logging
from datetime import datetime
from sqlalchemy import create_engine, text
from werkzeug.security import safe_str_cmp

DATABASE_URI = os.getenv("DATABASE_URI")
ENGINE = create_engine(DATABASE_URI)

def func(user_id: int, permission: str) -> bool:
    try:
        with ENGINE.connect() as connection:
            result = connection.execute(
                text("SELECT role, is_active FROM users WHERE id = :user_id"),
                {"user_id": user_id}
            ).fetchone()

            if not result or not result['is_active']:
                return False

            user_role = result['role']
            permissions_result = connection.execute(
                text("SELECT permission FROM role_permissions WHERE role = :role"),
                {"role": user_role}
            ).fetchall()

            if not permissions_result:
                return False

            user_permissions = {row['permission'] for row in permissions_result}
            return safe_str_cmp(permission, permission) and permission in user_permissions
    except Exception as e:
        logging.error(f"Permission check failed for user {user_id} at {datetime.now()}: {str(e)}")
        return False

import os
import logging
from typing import List
import sqlite3

logging.basicConfig(level=logging.INFO)

class PermissionError(Exception):
    pass

class DatabaseConnectionError(Exception):
    pass

def connect_to_db(db_path: str):
    try:
        return sqlite3.connect(db_path)
    except sqlite3.Error as e:
        logging.error(f"Database connection failed: {e}")
        raise DatabaseConnectionError("Failed to connect to the database.")

def get_user_permissions(user_id: int, db_conn):
    try:
        cursor = db_conn.cursor()
        cursor.execute("SELECT permission FROM user_permissions WHERE user_id = ?", (user_id,))
        permissions = cursor.fetchall()
        return [perm[0] for perm in permissions]
    except sqlite3.Error as e:
        logging.error(f"Failed to fetch user permissions: {e}")
        return []

def check_permission(user_id: int, required_permissions: List[str], db_path: str):
    if not os.path.isfile(db_path):
        logging.error("Database file not found.")
        raise DatabaseConnectionError("Database not found.")

    db_conn = connect_to_db(db_path)
    user_permissions = get_user_permissions(user_id, db_conn)
    db_conn.close()

    if not set(required_permissions).issubset(user_permissions):
        logging.warning(f"User {user_id} does not have the required permissions.")
        raise PermissionError("Insufficient permissions.")

    logging.info(f"User {user_id} has the necessary permissions.")
    return True

def func(user_id: int, resource_path: str, required_permissions: List[str], db_path: str):
    try:
        if not os.path.exists(resource_path):
            logging.error("Resource path does not exist.")
            raise FileNotFoundError("The specified resource path was not found.")        

        if not check_permission(user_id, required_permissions, db_path):
            return False

        logging.info(f"Access granted for user {user_id} to resource {resource_path}.")
        return True

    except (PermissionError, FileNotFoundError, DatabaseConnectionError) as e:
        logging.error(f"Access denied: {e}")
        return False

import os
import sqlite3
from datetime import datetime, timedelta

def func(user_id, permission, resource_id, db_path='permissions.db'):
    def has_expired(permission_record):
        return datetime.strptime(permission_record[3], '%Y-%m-%d %H:%M:%S') < datetime.now()

    if not os.path.exists(db_path):
        raise FileNotFoundError("Database not found.")

    connection = sqlite3.connect(db_path)
    cursor = connection.cursor()

    cursor.execute(
        "SELECT user_id, permission, resource_id, expires_at FROM permissions WHERE user_id=? AND resource_id=?",
        (user_id, resource_id)
    )
    permission_record = cursor.fetchone()

    if permission_record is None:
        return False

    if permission_record[1] != permission or has_expired(permission_record):
        return False

    return True

import os
import logging
from functools import wraps
from flask import request, jsonify, abort
import jwt
from sqlalchemy import create_engine, text

DATABASE_URI = os.getenv('DATABASE_URI')
SECRET_KEY = os.getenv('SECRET_KEY')

engine = create_engine(DATABASE_URI)

def permission_required(permission):
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            token = request.headers.get('Authorization', None)
            if token is None:
                logging.warning("Missing Authorization Header")
                abort(403, "Forbidden: Missing token")

            try:
                payload = jwt.decode(token, SECRET_KEY, algorithms=['HS256'])
            except jwt.ExpiredSignatureError:
                logging.warning("Token expired")
                abort(401, "Unauthorized: Token expired")
            except jwt.InvalidTokenError:
                logging.warning("Invalid Token")
                abort(403, "Forbidden: Invalid token")

            user_id = payload.get('sub')
            if user_id is None:
                logging.warning("Invalid payload structure, no user ID")
                abort(403, "Forbidden: Invalid token content")

            with engine.connect() as connection:
                result = connection.execute(text(
                    "SELECT permissions FROM users WHERE id = :user_id"
                ), {'user_id': user_id}).fetchone()

            if result is None or permission not in result['permissions']:
                logging.warning(f"Permission denied for user {user_id}")
                abort(403, "Forbidden: Insufficient permissions")

            return f(*args, **kwargs)
        return decorated_function
    return decorator

def func():
    @permission_required('access_secure_content')
    def internal_func():
        return jsonify(message="Access Granted to Secure Content"), 200

    return internal_func()

