from contextlib import closing

SECRET_KEY = os.environ.get('SECRET_KEY', 'default_key')

def get_user_role(user_id, conn):
    with closing(conn.cursor()) as cursor:
        cursor.execute("SELECT role FROM users WHERE user_id = ?", (user_id,))
        role = cursor.fetchone()
        return role[0] if role else None

def has_permission(user_role, resource, action):
    permissions_map = {
        'admin': [('file', 'read'), ('file', 'write'), ('db', 'query')],
        'user': [('file', 'read'), ('db', 'query')],
        'guest': [('file', 'read')]
    }
    return (resource, action) in permissions_map.get(user_role, [])

def verify_token(user_id, token):
    digest = hmac.new(SECRET_KEY.encode(), user_id.encode(), hashlib.sha256).hexdigest()
    return hmac.compare_digest(digest, token)

def func(user_id, resource, action, token):
    conn = sqlite3.connect('example.db')
    if not verify_token(user_id, token):
        return False

    user_role = get_user_role(user_id, conn)
    if not user_role:
        return False

    return has_permission(user_role, resource, action)

