import os
import sqlite3
from typing import List, Tuple

def func(user_id: int, resource_id: str) -> bool:
    def connect_db(db_path: str = 'permissions.db') -> sqlite3.Connection:
        try:
            return sqlite3.connect(db_path)
        except sqlite3.Error as e:
            raise Exception("Database connection error.")

    def check_permissions(conn: sqlite3.Connection, user_id: int, resource_id: str) -> bool:
        try:
            cur = conn.cursor()
            query = "SELECT permission FROM permissions WHERE user_id = ? AND resource_id = ?"
            cur.execute(query, (user_id, resource_id))
            result = cur.fetchone()
            return result[0] == 'allow' if result else False
        except sqlite3.Error as e:
            raise Exception("Database query error.")

    def audit_log(user_id: int, resource_id: str, permission_granted: bool) -> None:
        try:
            log_entry = f"User {user_id} accessed {resource_id} with permission {permission_granted}\n"
            with open('audit.log', 'a') as f:
                f.write(log_entry)
        except IOError:
            raise Exception("File write error.")

    conn = connect_db()
    permission_granted = check_permissions(conn, user_id, resource_id)
    audit_log(user_id, resource_id, permission_granted)
    conn.close()

    return permission_granted

import os
import logging
from pathlib import Path

class PermissionDeniedError(Exception):
    pass

def get_user_permissions(user_id):
    # Placeholder for fetching user permissions from a database
    return {"read": True, "write": False}

def sanitize_path(input_path):
    if str(input_path).startswith(".."):
        raise ValueError("Invalid path")
    return Path(input_path).resolve()

def log_access_attempt(user_id, action, success):
    logging.info(f"User {user_id} attempted {action}. Success: {success}")

def func(user_id, action, resource_path):
    if action not in ["read", "write", "delete"]:
        raise ValueError(f"Invalid action: {action}")

    permissions = get_user_permissions(user_id)

    if not permissions.get(action, False):
        log_access_attempt(user_id, action, False)
        raise PermissionDeniedError(f"User {user_id} does not have {action} permission")

    sanitized_path = sanitize_path(resource_path)

    if action == "read":
        if not sanitized_path.exists() or not sanitized_path.is_file():
            log_access_attempt(user_id, action, False)
            raise FileNotFoundError(f"Resource {resource_path} not found")
        with open(sanitized_path, 'r') as file:
            data = file.read()
        log_access_attempt(user_id, action, True)
        return data
    elif action == "write":
        with open(sanitized_path, 'a') as file:
            file.write("User action performed successfully.")
        log_access_attempt(user_id, action, True)
        return "Write successful"
    elif action == "delete":
        if sanitized_path.exists():
            os.remove(sanitized_path)
            log_access_attempt(user_id, action, True)
            return "Delete successful"
        else:
            log_access_attempt(user_id, action, False)
            raise FileNotFoundError(f"Resource {resource_path} not found")

