def func(user_id: int, resource_id: str) -> Optional[str]:
    def get_db_connection():
        return psycopg2.connect(
            host=DB_HOST,
            database=DB_NAME,
            user=DB_USER,
            password=DB_PASSWORD
        )

    def get_user_permissions(cur, uid: int):
        cur.execute("SELECT permissions FROM users WHERE id = %s", (uid,))
        row = cur.fetchone()
        if row:
            cipher_suite = Fernet(SECRET_KEY.encode())
            decrypted_permissions = cipher_suite.decrypt(row[0].encode()).decode()
            return set(decrypted_permissions.split(','))
        return set()

    def get_resource_requirements(cur, rid: str):
        cur.execute("SELECT required_permissions FROM resources WHERE id = %s", (rid,))
        row = cur.fetchone()
        if row:
            return set(row[0].split(','))
        return set()

