import hmac
from datetime import datetime, timedelta

def func(user_id, resource_id, action, user_roles, secret_key):
    def load_permissions():
        with open('permissions.json', 'r') as file:
            return json.load(file)

    def has_permission(permissions, role, action, resource):
        role_permissions = permissions.get(role, {})
        allowed_actions = role_permissions.get(resource, [])
        return action in allowed_actions

    def is_action_logged(resource, action, log_file='access.log'):
        try:
            with open(log_file, 'r') as file:
                for line in file:
                    if f"{resource}:{action}" in line:
                        return True
        except FileNotFoundError:
            return False
        return False

    def log_access_attempt(user_id, resource_id, action, result, log_file='access.log'):
        with open(log_file, 'a') as file:
            timestamp = datetime.utcnow().isoformat()
            log_entry = f"{timestamp}, User: {user_id}, Resource: {resource_id}, Action: {action}, Result: {result}\n"
            file.write(log_entry)

    def verify_request_signature(data, signature):
        calculated_signature = hmac.new(secret_key.encode(), data.encode(), hashlib.sha256).hexdigest()
        return hmac.compare_digest(calculated_signature, signature)

    permissions = load_permissions()

    if not all((user_id, resource_id, action)):
        log_access_attempt(user_id, resource_id, action, 'DENIED')
        return "DENIED"

    if is_action_logged(resource_id, action):
        return "DENIED"

    for role in user_roles:
        if has_permission(permissions, role, action, resource_id):
            log_access_attempt(user_id, resource_id, action, 'GRANTED')
            return "GRANTED"

    log_access_attempt(user_id, resource_id, action, 'DENIED')
    return "DENIED"

