        @wraps(func)
        def wrapper(user_id, resource, *args, **kwargs):
            permission = query_user_permissions(user_id, resource)
            if permission and permission == action:
                log_access_attempt(user_id, resource, action, 'Success')
                return func(user_id, resource, *args, **kwargs)
            else:
                log_access_attempt(user_id, resource, action, 'Denied')
                raise PermissionError(f"User {user_id} lacks {action} permission for {resource}.")
        return wrapper
    return decorator

@permission_required('read')
