import os
import logging
from functools import wraps
import sqlite3
from cryptography.hazmat.primitives.kdf.pbkdf2 import PBKDF2HMAC
from cryptography.hazmat.backends import default_backend
from cryptography.hazmat.primitives import hashes

logging.basicConfig(level=logging.INFO)

def connect_db():
    conn = sqlite3.connect('permissions.db')
    return conn

def secure_hash(password, salt):
    kdf = PBKDF2HMAC(
        algorithm=hashes.SHA256,
        length=32,
        salt=salt,
        iterations=100000,
        backend=default_backend()
    )
    return kdf.derive(password.encode())

def permission_required(permission):
    def decorator(func):
        @wraps(func)
        def wrapper(user_id, *args, **kwargs):
            conn = connect_db()
            cursor = conn.cursor()
            cursor.execute("SELECT permissions FROM users WHERE id=?", (user_id,))
            user_permissions = cursor.fetchone()
            conn.close()
            if not user_permissions or permission not in user_permissions[0].split(','):
                logging.warning(f'User {user_id} lacks {permission} permission')
                return False
            return func(user_id, *args, **kwargs)
        return wrapper
    return decorator

