def func(user_id, resource_id, required_permission, db_session):
    from sqlalchemy.orm import sessionmaker
    from sqlalchemy.exc import SQLAlchemyError
    from hashlib import sha256
    from datetime import datetime

    ResourceAccess = db_session.get_bind().table('ResourceAccess')
    UserPermissions = db_session.get_bind().table('UserPermissions')

    try:
        query_permission = db_session.query(
            UserPermissions.c.permission
        ).filter(
            UserPermissions.c.user_id == sha256(user_id.encode()).hexdigest(),
            UserPermissions.c.resource_id == sha256(resource_id.encode()).hexdigest()
        ).one_or_none()

        if not query_permission:
            return False

        permission_match = query_permission[0] == required_permission
        if not permission_match:
            return False

        access_log_query = db_session.query(
            ResourceAccess.c.timestamp
        ).filter(
            ResourceAccess.c.user_id == user_id,
            ResourceAccess.c.resource_id == resource_id
        ).order_by(
            ResourceAccess.c.timestamp.desc()
        ).first()

        if access_log_query:
