            if (datetime.utcnow() - last_access_time).total_seconds() < 60:
                return False

        db_session.execute(
            ResourceAccess.insert().values(
                user_id=user_id, 
                resource_id=resource_id, 
                timestamp=datetime.utcnow()
            )
        )

        db_session.commit()
