    def decorator(func):
        @wraps(func)
        def wrapper(token: str, *args, **kwargs):
            user_id = authenticate(token)
            user_permissions = fetch_user_permissions(user_id)
            if required_permission not in user_permissions:
                raise PermissionError(f"User does not have the required permission: {required_permission}")
            return func(user_id, *args, **kwargs)
        return wrapper
    return decorator

