    with engine.connect() as conn:
        query = text("INSERT INTO audit_logs (user_id, resource_id, permitted) VALUES (:user_id, :resource_id, :permitted)")
        conn.execute(query, user_id=user_id, resource_id=resource_id, permitted=permitted)

