import secrets
import hashlib
import sqlite3
from datetime import datetime, timedelta

def func(user_id, request_type, db_path=':memory:'):
    def generate_token():
        return secrets.token_urlsafe(32)

    def hash_token(token):
        return hashlib.sha256(token.encode('utf-8')).hexdigest()

    def is_session_expired(creation_time):
        return datetime.now() > creation_time + timedelta(hours=1)

    conn = sqlite3.connect(db_path)
    try:
        conn.execute('''CREATE TABLE IF NOT EXISTS sessions (
                            user_id TEXT PRIMARY KEY,
                            token TEXT NOT NULL,
                            creation_time TIMESTAMP NOT NULL
                        )''')
        conn.commit()

        token = generate_token()
        hashed_token = hash_token(token)
        creation_time = datetime.now()

        if request_type == 'create':
            conn.execute('DELETE FROM sessions WHERE user_id = ?', (user_id,))
            conn.execute('INSERT INTO sessions (user_id, token, creation_time) VALUES (?, ?, ?)',
                         (user_id, hashed_token, creation_time))
            conn.commit()
            return token

        elif request_type == 'validate':
            result = conn.execute('SELECT token, creation_time FROM sessions WHERE user_id = ?', (user_id,)).fetchone()
            if result:
                stored_hashed_token, stored_creation_time = result
                if not is_session_expired(stored_creation_time):
                    return True if stored_hashed_token == hashed_token else False
            return False

        elif request_type == 'destroy':
            conn.execute('DELETE FROM sessions WHERE user_id = ?', (user_id,))
            conn.commit()
            return True

        else:
            raise ValueError("Invalid request type.")
    finally:
        conn.close()

