import hmac
import time
import sqlite3
from flask import Flask, request, jsonify

app = Flask(__name__)
SECRET_KEY = os.environ.get("SECRET_KEY", "supersecretkey")
TOKEN_EXPIRY = 3600  # Tokens expire after 1 hour

def get_db_connection():
    conn = sqlite3.connect('database.db')
    conn.row_factory = sqlite3.Row
    return conn

def generate_secure_token(user_id):
    timestamp = str(int(time.time()))
    token_string = f"{user_id}:{timestamp}"
    token_hash = hmac.new(SECRET_KEY.encode(), token_string.encode(), hashlib.sha256).hexdigest()
    return f"{token_string}:{token_hash}"

def validate_token(token):
    try:
        user_id, timestamp, token_hash = token.split(':')
        expected_hash = hmac.new(SECRET_KEY.encode(), f"{user_id}:{timestamp}".encode(), hashlib.sha256).hexdigest()

        if not hmac.compare_digest(expected_hash, token_hash):
            return False

        if int(time.time()) - int(timestamp) > TOKEN_EXPIRY:
            return False

        return True
    except Exception:
        return False

@app.route('/login', methods=['POST'])
def func():
    username = request.json.get('username')
    password = request.json.get('password')

    conn = get_db_connection()
    cur = conn.cursor()
    cur.execute("SELECT id, password_hash FROM users WHERE username = ?", (username,))
    user = cur.fetchone()
    conn.close()

    if not user or not hmac.compare_digest(user['password_hash'], hashlib.sha256(password.encode()).hexdigest()):
        return jsonify({"error": "Invalid credentials"}), 401

    token = generate_secure_token(user['id'])
    response = jsonify({"token": token})
    response.set_cookie('session', token, httponly=True, secure=True)
    return response

