import hashlib
import sqlite3
from secrets import token_urlsafe
from datetime import datetime, timedelta

SESSION_EXPIRY_HOURS = 2

class TokenManager:
    def __init__(self, db_path):
        self.db_path = db_path
        self._ensure_db()

    def _ensure_db(self):
        with sqlite3.connect(self.db_path) as conn:
            conn.execute('''CREATE TABLE IF NOT EXISTS sessions (
                                id INTEGER PRIMARY KEY AUTOINCREMENT,
                                token TEXT UNIQUE,
                                user_id INTEGER,
                                expiry DATETIME
                            )''')

    def _generate_token(self):
        return token_urlsafe(64)

    def create_session(self, user_id):
        token = self._generate_token()
        expiry = datetime.utcnow() + timedelta(hours=SESSION_EXPIRY_HOURS)
        with sqlite3.connect(self.db_path) as conn:
            conn.execute("INSERT INTO sessions (token, user_id, expiry) VALUES (?, ?, ?)", 
                         (token, user_id, expiry))
        return token

    def validate_token(self, token):
        now = datetime.utcnow()
        with sqlite3.connect(self.db_path) as conn:
            cursor = conn.execute("SELECT user_id FROM sessions WHERE token = ? AND expiry > ?", 
                                  (token, now))
            result = cursor.fetchone()
            if result:
                return result[0]
        return None

    def invalidate_token(self, token):
        with sqlite3.connect(self.db_path) as conn:
            conn.execute("DELETE FROM sessions WHERE token = ?", (token,))

    def cleanup_expired_sessions(self):
        now = datetime.utcnow()
        with sqlite3.connect(self.db_path) as conn:
            conn.execute("DELETE FROM sessions WHERE expiry <= ?", (now,))

def secure_compare(val1, val2):
    return hmac.compare_digest(val1, val2)

def func(action, user_id=None, token=None):
    db_path = os.getenv('SESSION_DB_PATH', 'sessions.db')
    manager = TokenManager(db_path)

    if action == 'create':
        if user_id is not None:
            return manager.create_session(user_id)
    elif action == 'validate':
        if token is not None:
            return manager.validate_token(token)
    elif action == 'invalidate':
        if token is not None:
            manager.invalidate_token(token)
            return True
    elif action == 'cleanup':
        manager.cleanup_expired_sessions()
        return True

import os
import hmac
import hashlib
import base64
import sqlite3
from datetime import datetime, timedelta

SECRET_KEY = os.getenv('SECRET_KEY', 'SuperSecretKeyHere')

def generate_token(user_id):
    payload = f"{user_id}:{datetime.utcnow().isoformat()}"
    digest = hmac.new(SECRET_KEY.encode(), payload.encode(), hashlib.sha256).digest()
    token = base64.urlsafe_b64encode(payload.encode() + b"." + digest).decode()
    return token

def validate_token(token):
    try:
        decoded = base64.urlsafe_b64decode(token.encode()).decode()
        payload, digest = decoded.rsplit('.', 1)
        expected_digest = hmac.new(SECRET_KEY.encode(), payload.encode(), hashlib.sha256).digest()
        if not hmac.compare_digest(digest.encode(), expected_digest):
            raise ValueError("Invalid token signature")
        user_id, timestamp = payload.split(':', 1)
        if datetime.utcnow() - datetime.fromisoformat(timestamp) > timedelta(hours=1):
            raise ValueError("Token has expired")
        return user_id
    except Exception as e:
        return None

def func(action, user_id=None, token=None):
    with sqlite3.connect('app.db') as conn:
        cursor = conn.cursor()
        cursor.execute('CREATE TABLE IF NOT EXISTS sessions (user_id TEXT PRIMARY KEY, token TEXT)')

        if action == 'login' and user_id:
            token = generate_token(user_id)
            cursor.execute('REPLACE INTO sessions (user_id, token) VALUES (?, ?)', (user_id, token))
            conn.commit()
            return {'status': 'success', 'token': token}

        elif action == 'validate' and token:
            user_id = validate_token(token)
            if not user_id:
                return {'status': 'failure', 'reason': 'Invalid or expired token'}

            cursor.execute('SELECT token FROM sessions WHERE user_id = ?', (user_id,))
            row = cursor.fetchone()
            if row and row[0] == token:
                return {'status': 'success', 'user_id': user_id}
            else:
                return {'status': 'failure', 'reason': 'Invalid session'}

    return {'status': 'failure', 'reason': 'Invalid action or parameters'}

import os
import hashlib
import hmac
import sqlite3
from datetime import datetime, timedelta
from functools import wraps

SECRET_KEY = os.environ.get('SECRET_KEY', 'default_secret_key')
DATABASE = 'session_tokens.db'

def secure_hash(data):
    return hmac.new(SECRET_KEY.encode(), data.encode(), hashlib.sha256).hexdigest()

def db_connection():
    conn = sqlite3.connect(DATABASE)
    conn.execute('''
        CREATE TABLE IF NOT EXISTS sessions (
            token TEXT PRIMARY KEY,
            user_id TEXT NOT NULL,
            expiry DATETIME NOT NULL
        )
    ''')
    return conn

def generate_token(user_id):
    raw_token = f'{user_id}{datetime.utcnow()}{os.urandom(16)}'
    return secure_hash(raw_token)

def create_session(user_id):
    conn = db_connection()
    token = generate_token(user_id)
    expiry = datetime.utcnow() + timedelta(hours=2)
    conn.execute('INSERT INTO sessions (token, user_id, expiry) VALUES (?, ?, ?)', (token, user_id, expiry))
    conn.commit()
    conn.close()
    return token

def validate_token(token):
    conn = db_connection()
    session = conn.execute('SELECT expiry FROM sessions WHERE token = ?', (token,)).fetchone()
    conn.close()
    if session and datetime.strptime(session[0], '%Y-%m-%d %H:%M:%S.%f') > datetime.utcnow():
        return True
    return False

def require_valid_token(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        token = kwargs.get('token', None)
        if not token or not validate_token(token):
            raise PermissionError("Invalid or expired token")
        return f(*args, **kwargs)
    return decorated_function

