def func(user_id, operation):
    conn = sqlite3.connect(DATABASE)
    cur = conn.cursor()

    cur.execute('CREATE TABLE IF NOT EXISTS sessions (token TEXT PRIMARY KEY, user_id INTEGER, expires_at TEXT)')
    now = datetime.utcnow()
    cur.execute('DELETE FROM sessions WHERE expires_at <= ?', (now,))
    conn.commit()

    def generate_token():
        return secrets.token_urlsafe(32)

    def hash_token(token):
        return hmac.new(SECRET_KEY.encode(), token.encode(), hashlib.sha256).hexdigest()

    def create_session(user_id):
        token = generate_token()
        hashed_token = hash_token(token)
        expires_at = now + timedelta(hours=1)
        cur.execute('INSERT INTO sessions (token, user_id, expires_at) VALUES (?, ?, ?)', 
                    (hashed_token, user_id, expires_at))
