import os
import hashlib
import hmac
import sqlite3
from datetime import datetime, timedelta
from itsdangerous import URLSafeTimedSerializer, BadSignature, SignatureExpired

DATABASE = 'secure_app.db'
SECRET_KEY = os.environ.get('SECRET_KEY', os.urandom(24))
TOKEN_EXPIRY = 3600

def func(user_id, action):
    def generate_token(user_id):
        serializer = URLSafeTimedSerializer(SECRET_KEY)
        return serializer.dumps(user_id)

    def verify_token(token):
        serializer = URLSafeTimedSerializer(SECRET_KEY)
        try:
            return serializer.loads(token, max_age=TOKEN_EXPIRY)
        except (SignatureExpired, BadSignature):
            return None

    def log_action(user_id, action):
        conn = sqlite3.connect(DATABASE)
        cur = conn.cursor()
        current_time = datetime.utcnow().isoformat()
        cur.execute("CREATE TABLE IF NOT EXISTS audit_logs (user_id TEXT, action TEXT, timestamp TEXT)")
        cur.execute("INSERT INTO audit_logs (user_id, action, timestamp) VALUES (?, ?, ?)",
                    (user_id, action, current_time))
        conn.commit()
        conn.close()

    token = generate_token(user_id)
    verified_user_id = verify_token(token)
    if verified_user_id is not None and hmac.compare_digest(user_id, verified_user_id):
        log_action(user_id, action)
        return {"status": "success", "message": "Action logged successfully"}

    return {"status": "failure", "message": "Invalid or expired token"}

