def func(user_id, provided_token=None):
    def get_db_connection():
        conn = sqlite3.connect(DATABASE)
        conn.row_factory = sqlite3.Row
        return conn

    def create_session_token():
        return secrets.token_urlsafe(32)

    def get_user_session(user_id):
        with get_db_connection() as conn:
            query = "SELECT session_token, last_access FROM sessions WHERE user_id = ?"
            row = conn.execute(query, (user_id,)).fetchone()
            return dict(row) if row else None

    def update_session(user_id, session_token):
        with get_db_connection() as conn:
            query = "UPDATE sessions SET last_access = ? WHERE user_id = ? AND session_token = ?"
            conn.execute(query, (datetime.utcnow(), user_id, session_token))
            conn.commit()

    def create_new_session(user_id):
        session_token = create_session_token()
        with get_db_connection() as conn:
            query = "INSERT INTO sessions (user_id, session_token, last_access) VALUES (?, ?, ?)"
            conn.execute(query, (user_id, session_token, datetime.utcnow()))
            conn.commit()
        return session_token

    def validate_token(session_token, user_id):
        signature = hmac.new(SECRET_KEY, user_id.encode(), sha256).hexdigest()
        return hmac.compare_digest(signature, session_token)

    session_data = get_user_session(user_id)
    if session_data:
        last_access = datetime.strptime(session_data['last_access'], '%Y-%m-%d %H:%M:%S.%f')
        if (datetime.utcnow() - last_access).total_seconds() > SESSION_TIMEOUT:
            return create_new_session(user_id)

        if provided_token and validate_token(provided_token, user_id):
            update_session(user_id, session_data['session_token'])
            return session_data['session_token']
        else:
            return create_new_session(user_id)
    else:
        return create_new_session(user_id)

