        expiry = datetime.utcnow() + timedelta(hours=TOKEN_EXPIRY_HOURS)
        conn.execute('INSERT INTO sessions (user_id, token_hash, expiry) VALUES (?, ?, ?)',
                     (user_id, hashed_token, expiry))
        conn.commit()
        conn.close()
        return token

    def validate_session(token):
        conn = get_db_connection()
        hashed_token = hash_token(token)
        session = conn.execute('SELECT * FROM sessions WHERE token_hash = ?', (hashed_token,)).fetchone()
        conn.close()
        if session and datetime.strptime(session['expiry'], '%Y-%m-%d %H:%M:%S') > datetime.utcnow():
            return True
        return False

    def cleanup_expired_sessions():
        conn = get_db_connection()
        conn.execute('DELETE FROM sessions WHERE expiry < ?', (datetime.utcnow(),))
        conn.commit()
        conn.close()

    if action == 'create':
        return create_session(user_id)
    elif action == 'validate':
        return validate_session(user_id)  # User ID here is assumed to be the token for validation
    elif action == 'cleanup':
        cleanup_expired_sessions()
        return 'Cleanup complete'
    else:
        raise ValueError('Invalid action')

