from sqlalchemy import create_engine, Table, Column, String, DateTime, MetaData, select, and_
from sqlalchemy.exc import SQLAlchemyError

DATABASE_URL = os.getenv('DATABASE_URL', 'sqlite:///tokens.db')
TOKEN_EXPIRY_HOURS = 24

engine = create_engine(DATABASE_URL)
metadata = MetaData()

tokens_table = Table(
    'tokens', metadata,
    Column('token', String(128), primary_key=True),
    Column('user_id', String(64), nullable=False),
    Column('expires_at', DateTime, nullable=False)
)

def init_db():
    metadata.create_all(engine)

def func(user_id: str) -> str:
    def generate_token() -> str:
        return secrets.token_urlsafe(64)

    def store_token(user_id: str, token: str, expires_at: datetime):
        try:
            with engine.connect() as conn:
                conn.execute(
                    tokens_table.insert().values(
                        token=token,
                        user_id=user_id,
                        expires_at=expires_at
                    )
                )
        except SQLAlchemyError as e:
            raise RuntimeError("Database error") from e

    def validate_token(user_id: str, token: str) -> bool:
        try:
            with engine.connect() as conn:
                result = conn.execute(
                    select([tokens_table.c.expires_at]).where(
                        and_(
                            tokens_table.c.user_id == user_id,
                            tokens_table.c.token == token
                        )
                    )
                ).fetchone()
                if result is None:
                    return False
                return datetime.utcnow() < result['expires_at']
        except SQLAlchemyError:
            return False

    new_token = generate_token()
    expires_at = datetime.utcnow() + timedelta(hours=TOKEN_EXPIRY_HOURS)

    if not validate_token(user_id, new_token):
        store_token(user_id, new_token, expires_at)

    return new_token

