import hmac
import json
from datetime import datetime, timedelta
import sqlite3

SECRET_KEY = os.environ.get("SECRET_KEY", "default_secret_key")
TOKEN_VALIDITY_PERIOD = timedelta(hours=1)

def generate_secure_token(user_id):
    timestamp = datetime.utcnow().strftime('%Y-%m-%d %H:%M:%S')
    data = f"{user_id}{timestamp}".encode('utf-8')
    return hmac.new(SECRET_KEY.encode('utf-8'), data, hashlib.sha256).hexdigest(), timestamp

def store_session_in_db(user_id, token, timestamp):
    conn = sqlite3.connect('sessions.db')
    cursor = conn.cursor()
    cursor.execute('''
        CREATE TABLE IF NOT EXISTS sessions (
            user_id TEXT,
            token TEXT,
            timestamp TEXT
        )
    ''')
    cursor.execute('''
        INSERT INTO sessions (user_id, token, timestamp) VALUES (?, ?, ?)
    ''', (user_id, token, timestamp))
    conn.commit()
    conn.close()

def is_token_valid(user_id, token):
    conn = sqlite3.connect('sessions.db')
    cursor = conn.cursor()
    cursor.execute('''
        SELECT timestamp FROM sessions WHERE user_id=? AND token=?
    ''', (user_id, token))
    result = cursor.fetchone()
    conn.close()
    if result:
        token_time = datetime.strptime(result[0], '%Y-%m-%d %H:%M:%S')
        if datetime.utcnow() - token_time < TOKEN_VALIDITY_PERIOD:
            return True
    return False

def authenticate_request(request):
    auth_header = request.headers.get('Authorization')
    if not auth_header:
        return False

    try:
        auth_type, token = auth_header.split(' ')
        if auth_type.lower() != 'bearer':
            return False
    except ValueError:
        return False

    user_id = request.headers.get('User-ID')
    if not user_id:
        return False

    return is_token_valid(user_id, token)

