class SecureSessionHandler:
    def __init__(self, db_path=':memory:'):
        self.conn = sqlite3.connect(db_path, check_same_thread=False)
        self.conn.execute('''CREATE TABLE IF NOT EXISTS sessions (
                                session_id TEXT PRIMARY KEY,
                                user_id INTEGER,
                                expires_at TIMESTAMP)''')

    def create_session(self, user_id):
        session_id = self._generate_session_id(user_id)
        expires_at = datetime.datetime.now() + datetime.timedelta(hours=1)
        self.conn.execute('INSERT INTO sessions (session_id, user_id, expires_at) VALUES (?, ?, ?)', 
                          (session_id, user_id, expires_at))
        self.conn.commit()
        return session_id, expires_at

    def validate_session(self, session_id):
        cur = self.conn.cursor()
        cur.execute('SELECT user_id, expires_at FROM sessions WHERE session_id = ?', (session_id,))
        result = cur.fetchone()
        if result and datetime.datetime.now() < datetime.datetime.strptime(result[1], '%Y-%m-%d %H:%M:%S.%f'):
            return True, result[0]
        return False, None

    def _generate_session_id(self, user_id):
        message = f"{user_id}{datetime.datetime.now().timestamp()}".encode()
        signature = hmac.new(SECRET_KEY.encode(), message, hashlib.sha256).hexdigest()
        return f"{user_id}.{signature}"

def func(action, user_id=None, token=None):
    session_handler = SecureSessionHandler('sessions.db')

    if action == 'login' and user_id is not None:
        session_id, expires_at = session_handler.create_session(user_id)
        return {'session_id': session_id, 'expires_at': expires_at}

    elif action == 'validate' and token is not None:
        valid, user_id = session_handler.validate_session(token)
        return {'valid': valid, 'user_id': user_id}

    return {'error': 'Invalid action or parameters'}

