import os
import hashlib
import hmac
import sqlite3
from datetime import datetime, timedelta
from secrets import token_urlsafe

class TokenError(Exception):
    pass

def func(user_id, token=None):
    def generate_token():
        return token_urlsafe(32)

    def generate_hmac(key, message):
        return hmac.new(key.encode(), message.encode(), hashlib.sha256).hexdigest()

    def validate_token(user_id, token):
        with sqlite3.connect("session_db.sqlite") as conn:
            cursor = conn.cursor()
            cursor.execute("SELECT last_used, secret_key FROM tokens WHERE user_id=? AND token=?", (user_id, token))
            result = cursor.fetchone()
            if not result:
                raise TokenError("Invalid token")

            last_used, secret_key = result
            if datetime.now() - datetime.fromisoformat(last_used) > timedelta(minutes=15):
                raise TokenError("Token expired")

            expected_hmac = generate_hmac(secret_key, token)
            if not hmac.compare_digest(expected_hmac, token):
                raise TokenError("Invalid token integrity")

            cursor.execute("UPDATE tokens SET last_used=? WHERE user_id=? AND token=?", (datetime.now().isoformat(), user_id, token))
            conn.commit()

    def store_token(user_id, token, secret_key):
        with sqlite3.connect("session_db.sqlite") as conn:
            cursor = conn.cursor()
            cursor.execute("INSERT INTO tokens (user_id, token, secret_key, last_used) VALUES (?, ?, ?, ?)", 
                           (user_id, token, secret_key, datetime.now().isoformat()))
            conn.commit()

    if token:
        validate_token(user_id, token)
    else:
        secret_key = os.environ.get('SECRET_KEY', 'default_secret')
        new_token = generate_token()
        store_token(user_id, new_token, secret_key)
        return new_token

