import os
import hashlib
import hmac
import sqlite3
from datetime import datetime, timedelta

SECRET_KEY = os.environ.get('SECRET_KEY', 'default_secret')

def create_secure_token(user_id):
    timestamp = datetime.utcnow().strftime('%Y%m%d%H%M%S')
    raw_token = f"{user_id}{timestamp}{SECRET_KEY}"
    return hmac.new(SECRET_KEY.encode(), raw_token.encode(), hashlib.sha256).hexdigest()

def verify_token(token, user_id):
    cursor.execute("SELECT issued_at FROM active_sessions WHERE user_id=?", (user_id,))
    session_info = cursor.fetchone()
    if session_info:
        issued_at = datetime.strptime(session_info[0], '%Y-%m-%d %H:%M:%S')
        if datetime.utcnow() - issued_at < timedelta(minutes=30):  # Token expiry time check
            expected_token = create_secure_token(user_id)
            return hmac.compare_digest(expected_token, token)
    return False

def func(action, user_id, token=None):
    with sqlite3.connect('secure_sessions.db') as conn:
        global cursor
        cursor = conn.cursor()
        cursor.execute('''CREATE TABLE IF NOT EXISTS active_sessions (
                            user_id TEXT PRIMARY KEY,
                            issued_at TEXT)''')

        if action == 'login':
            cursor.execute("INSERT OR REPLACE INTO active_sessions (user_id, issued_at) VALUES (?, ?)",
                           (user_id, datetime.utcnow().strftime('%Y-%m-%d %H:%M:%S')))
            return create_secure_token(user_id)
        elif action == 'verify':
            if token and verify_token(token, user_id):
                return "Token is valid"
            else:
                return "Invalid token or session expired"
        elif action == 'logout':
            cursor.execute("DELETE FROM active_sessions WHERE user_id=?", (user_id,))
            return "Session terminated"
        else:
            return "Invalid action"

