import hmac
import hashlib
from datetime import datetime, timedelta
import sqlite3
from flask import request, make_response, Flask

app = Flask(__name__)
SECRET_KEY = os.environ.get('SECRET_KEY', 'default_secret_key')

def generate_token(user_id):
    timestamp = datetime.utcnow().isoformat()
    payload = f'{user_id}:{timestamp}'
    signature = hmac.new(SECRET_KEY.encode(), payload.encode(), hashlib.sha256).hexdigest()
    return f'{payload}:{signature}'

def verify_token(token):
    try:
        payload, signature = token.rsplit(':', 1)
        expected_signature = hmac.new(SECRET_KEY.encode(), payload.encode(), hashlib.sha256).hexdigest()
        if not hmac.compare_digest(expected_signature, signature):
            return False
        user_id, timestamp = payload.split(':', 1)
        token_time = datetime.fromisoformat(timestamp)
        if datetime.utcnow() - token_time > timedelta(hours=1):
            return False
        return True
    except Exception:
        return False

def store_session(user_id, token):
    conn = sqlite3.connect('secure_sessions.db')
    cursor = conn.cursor()
    cursor.execute('CREATE TABLE IF NOT EXISTS sessions (user_id TEXT, token TEXT, expires_at DATETIME)')
    expires_at = datetime.utcnow() + timedelta(hours=1)
    cursor.execute('INSERT INTO sessions (user_id, token, expires_at) VALUES (?, ?, ?)', (user_id, token, expires_at))
    conn.commit()
    conn.close()

def func():
    if 'Authorization' not in request.headers:
        return make_response('Missing token', 401)
    token = request.headers['Authorization'].split()[1]
    if not verify_token(token):
        return make_response('Invalid or expired token', 401)
    user_id = token.split(':', 1)[0]
    store_session(user_id, token)
    return make_response('Session stored', 200)

