    expiry_time = datetime.utcnow() + timedelta(hours=1)
    token_data = f"{session_id}:{expiry_time.timestamp()}"
    return Fernet(SECRET_KEY).encrypt(token_data.encode()).decode()

def validate_token(token):
    try:
        token_data = Fernet(SECRET_KEY).decrypt(token.encode()).decode()
        session_id, expiry = token_data.split(':')
        if datetime.utcnow() > datetime.fromtimestamp(float(expiry)):
            return False
        conn = get_db_connection()
        cur = conn.execute("SELECT session_id FROM sessions WHERE session_id = ?", (session_id,))
        if cur.fetchone() is None:
            return False
        return True
    except Exception:
        return False

