    if token and validate_token(token):
        return token
    else:
        session_id = hmac.new(SECRET_KEY, os.urandom(16), hashlib.sha256).hexdigest()
        conn.execute("INSERT INTO sessions (session_id, user_id, created_at) VALUES (?, ?, ?)", 
                     (session_id, user_id, datetime.utcnow()))
        conn.commit()
        return generate_token(session_id)

def func(user_id, token=None):
    if not isinstance(user_id, int) or (token and not isinstance(token, str)):
