import os
import secrets
import sqlite3
from datetime import datetime, timedelta

class TokenManager:
    TOKEN_EXPIRY_DURATION = timedelta(hours=1)

    def __init__(self, db_path=':memory:'):
        self.conn = sqlite3.connect(db_path)
        self.create_table()

    def create_table(self):
        with self.conn:
            self.conn.execute('''
                CREATE TABLE IF NOT EXISTS sessions (
                    token TEXT PRIMARY KEY,
                    user_id INTEGER NOT NULL,
                    expiry DATETIME NOT NULL
                )
            ''')

    def generate_token(self, user_id):
        token = secrets.token_urlsafe(32)
        expiry = datetime.utcnow() + self.TOKEN_EXPIRY_DURATION
        with self.conn:
            self.conn.execute('''
                INSERT INTO sessions (token, user_id, expiry)
                VALUES (?, ?, ?)
            ''', (token, user_id, expiry))
        return token

    def validate_token(self, token):
        with self.conn:
            cursor = self.conn.execute('''
                SELECT user_id, expiry FROM sessions
                WHERE token = ?
            ''', (token,))
            row = cursor.fetchone()
            if row:
                user_id, expiry = row
                if datetime.utcnow() < datetime.fromisoformat(expiry):
                    return user_id
                self.revoke_token(token)
        return None

    def revoke_token(self, token):
        with self.conn:
            self.conn.execute('''
                DELETE FROM sessions WHERE token = ?
            ''', (token,))

def func(action, user_id=None, token=None):
    manager = TokenManager('secure_tokens.db')
    if action == 'generate':
        if not user_id:
            raise ValueError("User ID must be provided for token generation.")
        return manager.generate_token(user_id)
    elif action == 'validate':
        if not token:
            raise ValueError("Token must be provided for validation.")
        return manager.validate_token(token)
    elif action == 'revoke':
        if not token:
            raise ValueError("Token must be provided for revocation.")
        manager.revoke_token(token)
        return "Token revoked successfully."
    else:
        raise ValueError("Invalid action specified.")

