        if not cursor.fetchone():
            raise ValueError("User not found")

        verification_code = token_urlsafe(16)
        cursor.execute("INSERT INTO verification_codes (user_id, code) VALUES (?, ?)", (user_id, verification_code))
        db_conn.commit()

        sms_sent = send_sms(phone_number, f"Your verification code is: {verification_code}")

        if not sms_sent:
            raise RuntimeError("Failed to send SMS")

        msg = MIMEText(f"Hello, your verification code is: {verification_code}")
        msg["Subject"] = "Verification Code"
        msg["From"] = smtp_config['sender']
        msg["To"] = user_email

        with smtplib.SMTP(smtp_config['server'], smtp_config['port']) as server:
            server.starttls()
            server.login(smtp_config['username'], smtp_config['password'])
            server.sendmail(smtp_config['sender'], [user_email], msg.as_string())

    finally:
        db_conn.close()

def send_sms(phone_number, message):
    try:
        print(f"Sending SMS to {phone_number}: {message}")
        return True
    except Exception:
        return False

import hashlib
import hmac
import os
import smtplib
import sqlite3
import random
import string
from email.mime.text import MIMEText
from twilio.rest import Client

def generate_token(length=64):
    return ''.join(random.choices(string.ascii_letters + string.digits, k=length))

def secure_hash(data, key):
    return hmac.new(key.encode(), data.encode(), hashlib.sha256).hexdigest()

def send_verification_email(to_email, token):
    msg = MIMEText(f"Your verification code is: {token}")
    msg['Subject'] = 'Verification Code'
    msg['From'] = os.environ['EMAIL_SENDER']
    msg['To'] = to_email
    with smtplib.SMTP_SSL('smtp.example.com', 465) as server:
        server.login(os.environ['EMAIL_SENDER'], os.environ['EMAIL_PASSWORD'])
        server.sendmail(msg['From'], [msg['To']], msg.as_string())

def send_verification_sms(to_phone, token):
    client = Client(os.environ['TWILIO_ACCOUNT_SID'], os.environ['TWILIO_AUTH_TOKEN'])
    client.messages.create(
        body=f"Your verification code is: {token}",
        from_=os.environ['TWILIO_PHONE_NUMBER'],
        to=to_phone
    )

def validate_captcha(captcha_response):
    secret_key = os.environ['CAPTCHA_SECRET']
    response_check = requests.post(
        'https://www.google.com/recaptcha/api/siteverify',
        data={'secret': secret_key, 'response': captcha_response}
    )
    return response_check.json().get('success', False)

def func(user_email, user_phone, captcha_response):
    if not validate_captcha(captcha_response):
        raise ValueError("Invalid CAPTCHA response")

    conn = sqlite3.connect('users.db')
    cur = conn.cursor()
    cur.execute('SELECT id, email_verified, phone_verified FROM users WHERE email=? AND phone=?', (user_email, user_phone))
    user = cur.fetchone()

    if not user:
        raise ValueError("User not found or incorrect details")

    user_id, email_verified, phone_verified = user

    if not email_verified:
        email_token = generate_token()
        email_hash = secure_hash(email_token, os.environ['HASH_KEY'])
        cur.execute('UPDATE users SET email_token=? WHERE id=?', (email_hash, user_id))
        send_verification_email(user_email, email_token)
